// bom模板表单保存（废）
tempSysBomTemplateSaveAction(event: EventInterface): void {
    const com = event.contentComFn() as unknown as BaseComponent
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const triggerInstance = (com.dppRender as any)['triggerInstance']()

    const formService = this.getContentCom<DppFormComponent>(event).getService()
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const formData = formService.getFormModel<any>()
    console.log('d', formData)
    const params = {
        TEMPLATENAME: formData.TEMPLATENAME,
        TITLE: formData.TITLE,
        VIEWCLASSGUID: formData.VIEWCLASSNAME.guid,
        STRUCTURECLASSGUID: formData.STRUCTURECLASSNAME.guid,
        SEQUENCESTART: formData.SEQUENCESTART,
        SEQUENCEINCREMENT: formData.SEQUENCEINCREMENT,
        SEQUENCEPAD: formData.SEQUENCEPAD === true || formData.SEQUENCEPAD === 'Y' ? 'Y' : 'N',
        SEQUENCELENGTH: formData.SEQUENCELENGTH,
        MOVEFORWARD: formData.MOVEFORWARD === true || formData.MOVEFORWARD === 'Y' ? 'Y' : 'N',
        CHECKDESIGNATOR: formData.CHECKDESIGNATOR === true || formData.CHECKDESIGNATOR === 'Y' ? 'Y' : 'N',
        ISINCORPORATEDMASTER: formData.ISINCORPORATEDMASTER === true || formData.ISINCORPORATEDMASTER === 'Y' ? 'Y' : 'N',
        DESIGNATORSEPARATOR: formData.DESIGNATORSEPARATOR
    }
    this.bomManagement.updateBOMTemplate(params).subscribe({
        next: res => {
            if (res.success) {
                this.dppMessageService.success('common.operation.saveSuccess')
                triggerInstance.callback({
                    operate: EventCallbacksActionName.UPDATE,
                    params: { isKeepPage: true, ...res.data }
                })
            }
        }
    })
}

// BOM业务对象添加（废）
tempSysBomBusinessObjectAddAction(event: EventInterface): void {
    const rowData = this.getRowData(event) as any
    const params = {
        TEMPLATENAME: rowData.TEMPLATENAME,
        TITLE: rowData.TITLE,
        VIEWCLASSNAME: rowData.VIEWCLASSNAME,
