        ISINCORPORATEDMASTER: rowData.ISINCORPORATEDMASTER,
        DESIGNATORSEPARATOR: rowData.DESIGNATORSEPARATOR,
        TEMPLATEID: ''
    }
    const formParams: IFormRender = {
        mParams: {
            mode: ModeTypeEnum.EDIT,
            isObject: false
        },
        name: FormConfigModelEnum.ADDBUSINESSFORM
    }
    this.as.openModal<FormApi>(
        {
            title: 'systemSetting.bomTemplate.commonTitle.newTemplateWithBO',
            width: '600px',
            height: '200px',
            closable: true,
            uiType: 'form',
            openModalCloseDrawer: false,
            params: {
                dppRender: formParams
            },
            footer: [
                {
                    label: 'common.button.cancel',
                    type: 'default',
                    onClick: ctx => {
                        const formApi = ctx.getContentApi()
                        formApi.reset()
                        ctx.close()
                    }
                },
                {
                    label: 'common.button.confirm',
                    type: 'primary',
                    onClick: ctx => {
                        const formCpn = ctx.getContentApi()
                        const isValid = formCpn.onSubmit()
                        const formData = formCpn.getFormData()

                        params.TEMPLATEID = formData.ID ? formData.ID : formData.TEMPLATEID
                        if (isValid) {
                            formCpn.setLoading(true)
                            this.bomManagement.saveBOMTemplate(params).subscribe({
                                next: res => {
                                    formCpn.setLoading(false)
                                    if (res.success) {
                                        this.dppMessageService.success('common.operation.newSuccess')
                                        this.contentComCallback(event, {
                                            operate: EventCallbacksActionName.UPDATE,
                                            params: {
                                                ...res.data
                                            }
                                        })
                                    }
                                },
                                error: err => {
                                    formCpn.setLoading(false)
                                }
                            })
                            ctx.close()
                        }
                    }
                }
            ]
        }
    )
}

