// 报表编辑
tempSysReportFormsEditAction(event: EventInterface): void {
    const rowData = this.getRowData(event) as any
    const TEMPLATENAME = rowData['TEMPLATENAME']
    const GUID = rowData['GUID']
    const BOMREPORTTEMPLATENAME = rowData['BOMREPORTTEMPLATENAME']
    const formParams: IFormRender = {
        name: FormConfigModelEnum.NEWREPORTFORM,
        mParams: {
            mode: ModeTypeEnum.EDIT,
            isObject: false
        },
        dParams: {
            dataSource: `/bomTemplate/getBOMReportTemplateByGUID?TemplateName=${TEMPLATENAME}&BOMREPORTTEMPLATEGUID=${GUID}`
        }
    }
    const modal = this.as.openModal(
        {
            title: 'systemSetting.bomTemplate.command.EditReport',
            width: '600px',
            height: '400px',
            closable: true,
            content: DppFormComponent,
            openModalCloseDrawer: false,
            footer: [
                {
                    label: 'common.button.cancel',
                    type: 'default',
                    onClick: formCpn => {
                        formCpn.reset()
                        modal.close()
                    }
                },
                {
                    label: 'common.button.confirm',
                    type: 'primary',
                    onClick: formCpn => {
                        const formData = formCpn.getFormData()
                        const tableData = this.getData(event) as any
                        for (let i = 0; i < tableData.length; i++) {
                            if (tableData[i].BOMREPORTTEMPLATENAME === BOMREPORTTEMPLATENAME) {
                                tableData[i] = formData
                            }
                        }
                        const params = {
                            object: {
                                TEMPLATENAME,
                                ReportList: [...tableData]
                            }
                        }

                        const isValid = formCpn.onSubmit()
                        if (isValid) {
                            formCpn.setLoading(true)
                            this.bomManagement.updateBomTemplateReport(params).subscribe({
                                next: res => {
                                    formCpn.setLoading(false)
                                    if (res.success) {
                                        this.dppMessageService.success('common.operation.saveSuccess')
                                        this.contentComCallback(event, {
                                            operate: EventCallbacksActionName.UPDATE,
                                            params: {
                                                ...res.data
                                            }
                                        })
                                    }
                                },
                                error: err => {
                                    formCpn.setLoading(false)
                                }
                            })
                            modal.close()
                        }
                    }
                }
            ]
        },
        {
            dppRender: formParams
        }
    )
}

