// 添加父阶业务对象
addBomTemplateEnd1Action(event: EventInterface): void {
    const rowData = this.getRowData(event) as any
    this.bomManagement.listBizObject().subscribe(res => {
        const choose = (ctx: ActionModalFooterButtonHandler<DialogParams, SelectTreeComponent>): void => {

            const contentComp = ctx.getContentComponent() as SelectTreeComponent


            const chooseData = contentComp.getCheckedList()
            if (chooseData.length > 1) {
                this.dppMessageService.info('systemSetting.bomTemplate.message.end1BoLimitOne')
                return
            }

            const GUID = rowData.GUID
            this.bomManagement.updateRelationEnd1(GUID, chooseData[0] as string).subscribe(res => {
                ctx.close()
                const memberInstance = event.exeComFn() as any
                memberInstance['updateData']()
            })
        }
        this.as.openModal<SelectTreeComponent>(
            {
                title: 'systemSetting.bomTemplate.commonTitle.addEnd1Bo',
                width: '450px',
                height: '526px',
                openModalCloseDrawer: false,
                uiType: 'SelectTreeComponent',
                params: {
                    dppRender: res.data
                },
                footer: [
                    {
                        label: 'common.button.cancel',
                        type: 'default',
                        onClick: ctx => {
                            ctx.close()
                        }
                    },
                    {
                        label: 'common.button.confirm',
                        type: 'primary',
                        onClick: choose
                    }
                ],

            }
        )
    })
}

