// 添加子阶业务对象
addBomTemplateEnd2Action(event: EventInterface): void {
    const rowData = this.getRowData(event) as any
    const GUID = rowData.GUID
    const End2List = rowData.BOMTEMPLATEEND2LIST
    const defaultCheckedKeys = End2List.map((item: { KEY: string }) => item.KEY)
    this.bomManagement.listBizObject().subscribe(res => {
        const choose = (e: SelectTreeComponent): void => {
            const chooseData = e.getCheckedList()
            const End2List: Array<{ END2GUID: string }> = []
            chooseData.forEach(res => {
                End2List.push({
                    END2GUID: res as string
                })
            })
            console.log('d', End2List)
            this.bomManagement.updateRelationEnd2(GUID, End2List).subscribe(res => {
                modal.close()
                const memberInstance = event.exeComFn() as any
                memberInstance['updateData']()
            })
            if (chooseData.length > 1) return
        }
        const modal = this.as.openModal(
            {
                title: 'systemSetting.bomTemplate.commonTitle.addEnd2Bo',
                width: '450px',
                height: '526px',
                openModalCloseDrawer: false,
                footer: [
                    {
                        label: 'common.button.cancel',
                        type: 'default',
                        onClick: () => {
                            modal.close()
                        }
                    },
                    {
                        label: 'common.button.confirm',
                        type: 'primary',
                        onClick: choose
                    }
                ],
                content: SelectTreeComponent
            },
            { dppRender: res.data, defaultCheckedKeys }
        ) as NzModalRef
    })
}

// 删除子阶业务对象
deleteBomTemplateEnd2Action(event: EventInterface): void {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const rowData = this.getRowData(event) as any
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const memberInstance = event.exeComFn() as any
    const deleteEND2BONAME = memberInstance['removedTag'].END2BONAME
    const End2List: Array<{ END2GUID: string }> = []
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    rowData.BOMTEMPLATEEND2LIST.forEach((res: any) => {
        if (res.END2BONAME !== deleteEND2BONAME) {
            End2List.push({
                END2GUID: res.END2BONAME
            })
        }
    })
    const GUID = rowData.GUID
    this.bomManagement.updateRelationEnd2(GUID, End2List).subscribe(res => {
        this.dppMessageService.success('common.operation.deleteSuccess')
    })
}

