// 生失效BOM模板
async sysBomTemplateActiveAction(event: SwitchChangeEvent): Promise<void> {
    const newValue = event.newValue
    const data = event.data

    const applyBomTemplateChange = (): void => {
        const bomTemplateName = data['TEMPLATENAME']
        const ISVALID = newValue
        this.bomManagement.asyncToggleBomTemplate({ bomTemplateName, ISVALID }).then(res => {
            const table = event.beans.table
            table
                .refreshData()
                .pipe(take(1))
                .subscribe(() => {
                    const selectedNode = table.getSelectedNodeList()[0]
                    this.bomTool.refreshChildData(event as EventInterface, table, selectedNode)
                })
        })


    }

    if (newValue === 'Y') {
        applyBomTemplateChange()
    } else {
        const content = this.dpptranslate.transform('systemSetting.bomTemplate.prompt.templateInvalidWarning')
        const title = 'systemSetting.bomTemplate.field.warning'
        this.as.confirm(content, {
            title,
            footer: {
                nzOnOk: () => {
                    applyBomTemplateChange()
                },
                nzOnCancel: () => {
                    event.setLoading(false)
                }
            }
        })
    }
}

