/** Bom模板筛选
 * @param event EventInterface
 */
sysBomTemplateFilterAction(event: EventInterface): void {
    const table = this.getContentCom<DppTableComponent>(event)
    const filterFn = (): void => {
        const button = this.getExeCom<DppButtonComponent>(event)
        const value = button.value
        let condition: QueryConditionInfo[] = []
        if (value === 'Y') {
            condition = [new QueryConditionInfo('ISVALID', [value], 'EQUAL')]
        }

        table.refreshByCondition(condition).subscribe(res => {
            this.bomTool.refreshChildData(event as EventInterface, table)
        })
    }

    table.beans.event.conditionReady$.subscribe(res => {
        if (res) {
            filterFn()
        }
    })
}

/** bom关系筛选
 * @param event EventInterface
 */
sysBomRelationFilterAction(event: EventInterface): void {
    const table = this.getContentCom<DppTableComponent>(event)
    const rootPage = this.getRootPageService(event)
    const parentTable = rootPage.getComFnMapByName<DppTableComponent>('sysBomTemplateTableCommand')
    const selectNode = parentTable?.getSelectedNodeList()[0]
    const templateName = selectNode?.origin?.['TEMPLATENAME']
    const button = this.getExeCom<DppButtonComponent>(event)
    const value = button.value
    let condition: QueryConditionInfo[] = []
    condition = [new QueryConditionInfo('templateName', [templateName], 'EQUAL')]
    if (value === 'Y') {
        condition.push(new QueryConditionInfo('ISVALID', [value], 'EQUAL'))
    }
    table.refreshByCondition(condition)
}

