 * @type 单元格保存事件
 */
reviseAfterLifecycleAction(event: CellSaveEvent): Observable<DppResponse<NzSafeAny>> {
  const {data, newValue} = event;

  // 如果没有选择数据，则不进行保存
  if (!newValue || newValue.length === 0) {
    return of({ success: false, errorCode: '400', errorMsg: 'common.operation.operationFailed' });
  }

  let phaseSetList: {
    LCPHASEGUID?: string;
    ISREVISION?: string;
    REVISELCPHASEGUID?: string;
  } = {};
  if (data) {
    phaseSetList.LCPHASEGUID = data['BEFOREPHASE$'];
    phaseSetList.ISREVISION = data['ISREVISION'];
    phaseSetList.REVISELCPHASEGUID = data['AFTERPHASE$'];
  }
  const className = data['CLASSNAME'];
  const objects = {
    CLASSNAME: className,
    boPhaseSet: phaseSetList
  };
  return this.ruleManagementService.saveRevisionRule(objects).pipe(
    map(res => {
      this.messageService.success('common.operation.operationSuccess');
      res.data = undefined;
      return res;
    })
  );
}

