/**
 * @description 日历管理-例外日期-编辑表格单元格保存、表格添加行保存
 */
saveExceptionDateAction(event: CellSaveEvent): Observable<DppSafeAny> {
  let table = event.beans.table;
  let rowData = event.data;
  const datePipe = new DatePipe('zh-CN');

  const params = {
    GUID: rowData.GUID,
    DESCRIPTION: rowData?.['DESCRIPTION'],
    SPECIALNAME: rowData?.['SPECIALNAME'],
    CALENDARGUID: table.dppRender?.['dParams']?.['GUID'],
    CALENDARID: table.dppRender?.['dParams']?.['CALENDARID'],
    BEGINDATE: datePipe.transform(rowData?.['TIMERANGE']?.[0], 'yyyy-MM-dd', 'GMT+8'),
    ENDDATE: datePipe.transform(rowData?.['TIMERANGE']?.[1], 'yyyy-MM-dd', 'GMT+8'),
    ISNONWORKDAY: rowData['ISNONWORKDAY'],
    REPEATMODE: rowData['REPEATMODE'],
    GAPDAY: rowData['GAPDAY'],
    WEEKLYDAYS: rowData['WEEKLYDAYS'] || [],
    MONTHLYDAYS: rowData['MONTHLYDAYS'],
    YEARLYMONTHS: rowData['YEARLYMONTHS'],
    EXCEPTIONTIMES: rowData['EXCEPTIONTIMES'] || []
  };

  // 校验必填字段
  const RequireInfo = [];
  if (!params.SPECIALNAME) {
    RequireInfo.push(this.dpptranslate.transform('systemSetting.calender.field.Name'));
  }
  if (!params.BEGINDATE || !params.ENDDATE) {
    RequireInfo.push(this.dpptranslate.transform('systemSetting.classification.field.date'));
  }
  if (RequireInfo.length > 0) {
    this.dppMessageService.warning(
      this.dpptranslate.transform('systemSetting.calender.RequireInfo', {
        key: RequireInfo.join('、')
      })
    );
    return of(false);
  }

  // 校验字段长度
  const LengthInfo = [];
  if (this.getByteLength(this.dpptranslate.transform(rowData?.['SPECIALNAME'])) > 32) {
    LengthInfo.push(this.dpptranslate.transform('systemSetting.calender.field.Name'));
  }
  if (this.getByteLength(rowData?.['DESCRIPTION']) > 64) {
    LengthInfo.push(this.dpptranslate.transform('systemSetting.codeManagement.field.description'));
  }
  if (LengthInfo.length > 0) {
    this.dppMessageService.warning(
      this.dpptranslate.transform('systemSetting.calender.ExceedBytes', {
        key: LengthInfo.join('、')
      })
    );
    return of(false);
  }

  return new Observable(observer => {
    this.systemConfig.saveExceptionDate(params).subscribe(
      res => {
        if (res.success && res.data) {
          (table?.['calendarCom'] as CalendarManagementComponent)?.calendarTmpChange();
        }
      },
      error => {
        observer.error({
          success: false
        });
      }
    );
  });
}

private getByteLength(str: string): number {
  return new TextEncoder().encode(str || '').length;
}

