// 例外日期详情详情信息
sysExceptionDateDetailsAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const rowData = this.getRowData(event);
  if (!rowData.GUID) {
    this.dppMessageService.warning('systemSetting.calender.warning.SaveDataWarning');
    return;
  }
  const modal = this.as.openModal(
    {
      title: 'systemSetting.calender.command.sysDetailDateCommand',
      width: '800px',
      centered: true,
      content: ExceptionDateDetailsComponent,
      bodyStyle: { maxHeight: '100%', minHeight: '600px', padding: '20px', overflowY: 'scroll' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: (com: ExceptionDateDetailsComponent) => {
            // 内容组件
            const datePipe = new DatePipe('zh-CN');
            const params: CalendarList = {
              GUID: rowData.GUID,
              DESCRIPTION: com.exceptionDateData?.['DESCRIPTION'],
              SPECIALNAME: com.exceptionDateData?.SPECIALNAME,
              CALENDARGUID: com.exceptionDateData?.CALENDARGUID,
              CALENDARID: com.exceptionDateData?.CALENDARID,
              BEGINDATE: com.form?.getFormData()?.['STARTTIME']
                ? datePipe.transform(com.form?.getFormData()?.['STARTTIME'], 'yyyy-MM-dd', 'GMT+8')!
                : '',
              ENDDATE: com.form?.getFormData()?.['ENDTIME']
                ? datePipe.transform(com.form?.getFormData()?.['ENDTIME'], 'yyyy-MM-dd', 'GMT+8')!
                : '',
              ISNONWORKDAY: com.exceptionDateData?.ISNONWORKDAY,
              ...com.regularArg,
              EXCEPTIONTIMES: []
            };
            const timeTable = com.table;
            const tableData = timeTable.getTreeNodes();
            if (tableData?.length > 0) {
              params.EXCEPTIONTIMES = [];

              for (const item of tableData) {
                // 必选项校验
                if (!item?.origin['BEGINTIME'] || !item?.origin['ENDTIME']) {
                  const RequireInfo = [
                    this.dpptranslate.transform('systemSetting.calender.field.startTime'),
                    this.dpptranslate.transform('systemSetting.calender.field.EndTime')
                  ];
                  this.dppMessageService.warning(
                    this.dpptranslate.transform('systemSetting.calender.RequireInfo', {
                      key: RequireInfo.join('、')
                    })
                  );
                  return;
                }
                // 时间范围校验
                if (item?.origin['ENDTIME'].localeCompare(item?.origin['BEGINTIME']) === -1) {
                  this.dppMessageService.warning('systemSetting.calender.InvalidTimeRange');
                  return;
                }
              }

              params.EXCEPTIONTIMES = tableData.map(item => ({
                GUID: item.origin['GUID'],
                BEGINTIME: item.origin['BEGINTIME'],
                ENDTIME: item.origin['ENDTIME']
              }));
            }

            this.systemConfig.saveExceptionDate(params).subscribe(res => {
              if (res.success && res.data) {
                this.dppMessageService.success('common.operation.saveSuccess');
                modal?.close();
                table.refreshData();
                (table?.['calendarCom'] as CalendarManagementComponent)?.calendarTmpChange();
              }
            });
          }
        }
      ],
      canDrag: true
    },
    {
      dppRender: {
        name: 'tempSysNewMilestoneForm',
        mode: ModeTypeEnum.EDIT,
        GUID: rowData.GUID
      }
    }
  );
}

// 例外日期详情时间添加保存
sysExceptionDateDetailSaveAction(event: EventInterface): Observable<DppSafeAny> {
  let table = this.getContentCom(event) as DppTableComponent;
  !table ? (table = this.getExeCom(event) as DppTableComponent) : '';
  const rowData = this.getRowData(event);

  // 校验必填字段
  if (!rowData['BEGINTIME'] || !rowData['ENDTIME']) {
    this.dppMessageService.warning(
      this.dpptranslate.transform('systemSetting.calender.RequireInfo', {
        key: this.dpptranslate.transform('systemSetting.classification.field.time')
      })
    );
    return of(false);
  }

  // 校验时间大小
  if (rowData['ENDTIME'].localeCompare(rowData['BEGINTIME']) === -1) {
    this.dppMessageService.warning('systemSetting.calender.InvalidTimeRange');
    return of(false);
  }

  const exceptionDateData = table.dppRender?.dParams?.['exceptionDateData'];
  const regularArg = table.dppRender?.dParams?.['regularArg'];
  const form = table?.['exceptionDateDetails']?.form as DppFormComponent;
  const datePipe = new DatePipe('zh-CN');
  const params: CalendarList = {
    GUID: table.dppRender?.dParams?.['GUID'],
    DESCRIPTION: exceptionDateData?.['DESCRIPTION'],
    SPECIALNAME: exceptionDateData?.SPECIALNAME,
    CALENDARGUID: exceptionDateData?.CALENDARGUID,
    BEGINDATE: datePipe.transform(form?.getFormData()?.['STARTTIME'], 'yyyy-MM-dd', 'GMT+8')!,
    ENDDATE: datePipe.transform(form?.getFormData()?.['ENDTIME'], 'yyyy-MM-dd', 'GMT+8')!,
    ISNONWORKDAY: exceptionDateData?.ISNONWORKDAY,
    ...regularArg,
    EXCEPTIONTIMES: []
  };
  const tableData = table.getTreeNodes();
  if (tableData?.length > 0) {
    params.EXCEPTIONTIMES = [];
    tableData.forEach(item => {
      if (item && !item.origin['isNewRow']) {
        params.EXCEPTIONTIMES!.push({
          GUID: item.origin['GUID'],
          BEGINTIME: item.origin['BEGINTIME'],
          ENDTIME: item.origin['ENDTIME']
        });
      }
    });
  }

  params.EXCEPTIONTIMES!.push({
    GUID: rowData['GUID'],
    BEGINTIME: rowData['BEGINTIME'],
    ENDTIME: rowData['ENDTIME']
  });
  return new Observable(observer => {
    this.systemConfig.saveExceptionDate(params).subscribe(
      res => {
        if (res.success && res.data) {
          // table.refreshData();
          table?.['exceptionDateDetails']?.initData();
          table.dppRender.data = params.EXCEPTIONTIMES;
          observer.next({
            success: true,
            data: rowData
          });
        }
      },
      error => {
        observer.error({
          success: false
        });
      }
    );
  });
}

