// 打开合成规则表格
openSynthesisRulesModal(event: EventInterface, add?: boolean, rowData?: RowNode): DppNzModalRef {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as DppTableComponent;
  const dppRender = {
    name: 'sysClassificationAddSynthesisRulesTable',
    mParams: {
      total: false,
      toolbar: 'searchClassToolbar',
      dataSource: '/classfication/listRuleFields?classGuid=$classGuid$&classificationGuid=$classificationGuid'
    },
    dParams: {
      classGuid$: table?.dppRender?.dParams?.['classGuid$'],
      classificationGuid: table?.dppRender?.dParams?.['guid']
    },
    height: 'calc(100% - 40px)'
  };
  const modal = this.as.openModal(
    {
      title: 'systemSetting.classification.command.sysNewMergeRuleCommand',
      width: '1000px',
      centered: true,
      canDrag: true,
      content: DppTableComponent,
      bodyStyle: {
        width: 'auto',
        maxWidth: '1000px',
        height: 'calc(100vh - 340px)',
        padding: '20px',
        overflowY: 'scroll'
      },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
            this.setLoading(event, false);
          }
        },
        {
          label: 'systemSetting.classification.command.sysNewRuleCommand',
          type: 'primary',
          onClick: (com: DppTableComponent) => {
            console.log(com.getCheckedNodeList());
            // 内容组件
            const rulesData = com.getCheckedNodeList();
            if (!rulesData?.length) {
              return;
            }
            const params: any[] = [];
            let fieldFroms: string[] = [];
            for (let i = 0; i < rulesData.length; i++) {
              const item = rulesData[i];
              if (add) {
                // 新增操作
                params.push({
                  CLASSGUID: table?.dppRender?.dParams?.['classGuid$'],
                  CLASSIFICATIONITEMGUID: table?.dppRender?.dParams?.['guid'],
                  FIELDNAME: item?.origin?.['FIELDNAME'],
                  FORMAT: item?.origin?.['FORMAT'],
                  ISCLASSFIELD: item?.origin?.['ISCLASSFIELD'] || '',
                  ISNUMBERING: item?.origin?.['ISNUMBERING'],
                  STYLE: item?.origin?.['STYLE'],
                  TITLE: item?.origin?.['TITLE'] ? this.translation.transform(item?.origin?.['TITLE']) : null
                });
              } else {
                // 执行复制新增操作
                params.push(item?.origin?.['FIELDNAME']);
                fieldFroms.push(item?.origin?.['ISCLASSFIELD']);
              }
            }

            if (!add) {
              // 复制新增
              this.systemConfig
                .copyClassFeatureItem({
                  CLASSIFICATIONITEMGUID: table?.dppRender?.dParams?.['guid'],
                  CLASSGUID: table?.dppRender?.dParams?.['classGuid$'],
                  featureItemGuid: rowData?.origin?.['GUID'],
                  items: params,
                  fieldFroms
                })
                .subscribe(res => {
                  if (res.success && res.data) {
                    if (res.data.successCnt && res.data.successCnt === res.data?.totalCnt) {
                      this.dppMessageService.success('common.operation.newSuccess');
                    } else {
                      this.errorMessageService.showMessage(event, res);
                    }
                    if (res.data.successCnt) {
                      responseFn();
                    }
                  }
                });
            } else {
              this.systemConfig.saveFeatureItem(params).subscribe(res => {
                if (res.success && res.data) {
                  if (res.data.successCnt && res.data.successCnt === res.data?.totalCnt) {
                    this.dppMessageService.success('common.operation.newSuccess');
                  } else {
                    this.errorMessageService.showMessage(event, res);
                  }
                  if (res.data.successCnt) {
                    const successRuleArr = res.data.details
                      .filter(item => item.result == 'SUCCESS')
                      .map(item => item.data) as ClassificationFeatureItem[];
                    responseFn(successRuleArr[successRuleArr.length - 1]['FIELDNAME']);
                  }
                }
              });
            }
            modal?.close();
            this.setLoading(event, false);
          }
        }
      ]
    },
    {
      dppRender
    }
  );
  modal.afterClose.subscribe(res => {
    this.setLoading(event, false);
  });

  function responseFn(FIELDNAME?: string): void {
    table.refreshData().subscribe(res => {
      const bottomTable = table['bottomTable'] as DppTableComponent;
      const data = table.getTreeNodes();
      if (res.length > 0) {
        // if (add) {
        //   table.setNodeSelected(0);
        // } else {
        // }
        let index = FIELDNAME
          ? data.findIndex(item => item.origin['FIELDNAME'] == FIELDNAME)
          : data.findIndex(item => item.origin['GUID'] === rowData!.origin?.['GUID']);
        index = index == -1 ? 0 : index;
        // const index = data.findIndex(item => item.origin['GUID'] === rowData!.origin?.['GUID']) || 0;
        const selectedData = data[index].origin;
        table.setNodeSelected(index);
        bottomTable.dppRender!.dParams!['classficationFeatureItemguid'] = selectedData['GUID'];
        bottomTable.dppRender!.dParams!['ISINHERIT'] = selectedData['ISINHERIT'];
        bottomTable.topToolbar!.refresh();
        bottomTable?.refreshByParams({
          classficationFeatureItemguid: selectedData['GUID']
        });
      } else {
        bottomTable.dppRender!.dParams!['classficationFeatureItemguid'] = '';
        bottomTable?.refreshByParams({
          classficationFeatureItemguid: ''
        });
      }
    });
  }
  return modal;
}

