// 粘贴合成规则
sysClassificationPasteSynthesisRulesAction(event: EventInterface, data: ClassificationFeatureItem[]): void {
  this.setLoading(event, true);
  let pasteRulesParams = new Array();
  const table = this.getContentCom(event) as DppTableComponent;
  const rowData = table.getSelectedNodeList()?.[0]?.['origin'] as IFoundaton;
  if (!data) {
    const copySynthesisRulesOrigin = this.clipBoardService.getValuesByType(clipBoardTypeEnum.OBJECT_TYPE)!;
    const copySynthesisRules = this.systemConfig.deepCopySet(
      copySynthesisRulesOrigin
    ) as unknown as ClassificationFeatureItem[];
    if (!copySynthesisRules) {
      this.setLoading(event, false);
      this.dppMessageService.warning('classification.message.noCopyObject');
      return;
    }
    copySynthesisRules.forEach(item => {
      if (item?.['GUID'] && item['info']?.['FIELDNAME']) {
        delete item['GUID'];
        item['info']['CLASSGUID'] = table.dppRender.dParams!['classGuid$'];
        item['info']['CLASSIFICATIONITEMGUID'] = table.dppRender.dParams!['guid'];
        pasteRulesParams.push(item);
      }
    });
    if (pasteRulesParams.length === 0) {
      this.setLoading(event, false);
      // this.dppMessageService.warning('复制集合中不存在合成规则对象');
      return;
    }
  } else {
    pasteRulesParams = data;
  }
  pasteRulesParams = pasteRulesParams.map(item => {
    item.info.ONLYPASTENUMBER = true;
    return {
      ...item
    };
  });
  this.systemConfig.pasteFeatureItem(pasteRulesParams, false).subscribe({
    next: res => {
      this.setLoading(event, false);
      if (res.success && res.data) {
        // 测试数据
        // res.data = this.textData as any;
        const errorRuleArr = res.data!?.filter(i => i?.['ERRORTYPE']);
        const successRuleArr = res.data!?.filter(i => i?.['ERRORTYPE'] !== 'PASTE_ERROR');
        if (errorRuleArr && errorRuleArr.length > 0) {
          res.data.forEach(rule => {
            const CodeArr = rule['NUMBERFIELDS'] as IBatchData;
            const codeSegmentArr = [] as DppSafeAny[];
            CodeArr?.details?.forEach((code, index) => {
              let pasteChartSegment = '';
              if (code.data['FILLPOSITION$TITLE']) {
                pasteChartSegment = `${code.data['FILLPOSITION$TITLE']}补${code.data['FILLCHARACTER'] ? code.data['FILLCHARACTER'] : 0} ${code.data['CUTPOSITION$TITLE']}截取`;
              }
              codeSegmentArr.push({
                ...code.data,
                message: code.message,
                IDS: index + 1,
                pasteFieldType: code.data['FIELDTYPE$TITLE']
                  ? `${code.data['FIELDTYPE$TITLE']} ${code.data['TYPEVALUEEXTRA']}`
                  : '',
                pasteTYPEFIXED: code.data['TYPEFIXED'],
                pasteTypeValue: code.data['BASETYPEVALUE'],
                pasteChartSegment
              });
            });
            rule['CODES'] = codeSegmentArr;
          });
          this.pasteDataArr = res.data as any[];
          this.pasteDataArr = this.pasteDataArr.map((item, index) => ({
            ...item,
            IDS: index + 1
          }));
          console.log(this.pasteDataArr);

          // 打开错误原因弹窗
          this.dppMessageService.customBatchMessage(
            'error',
            {
              actionName: 'classification.message.pasteMergeRule',
              successCnt: pasteRulesParams?.length - errorRuleArr?.length,
              errorCnt: errorRuleArr?.length,
              warnCnt: 0,
              totalCnt: pasteRulesParams?.length
            },
            () => {
              const render: IRenderParameterNew<IUiModel> = {
                name: 'sysClassificationManagementPastePage',
                mParams: {
                  mode: ModeTypeEnum.EDIT,
                  canSet: 'N',
                  canExport: 'false',
                  canSize: 'N',
                  toolbar: 'sysClassifyRulesErrToolbar'
                },
                data: this.pasteDataArr as unknown as Record<string, unknown>,
                dParams: { ...table.dppRender.dParams }
              };
              const modal = this.as.openModal(
                {
                  title: 'classification.message.pasteMergeRule',
                  uiType: 'page',
                  bodyStyle: { height: '70vh' },
                  triggerInstance: () => table,
                  footer: [
                    {
                      label: 'common.button.cancel',
                      type: 'default',
                      onClick: (): void => {
                        modal?.close();
                        this.setLoading(event, false);
                      }
                    },
                    {
                      label: 'systemSetting.classification.command.sysPasteObjectCommand',
                      type: 'primary',
                      onClick: (com: DppTableComponent): void => {
                        this.setLoading(event, false);
                        const newParamsRules: any = [];
                        const hasWarningData = this.pasteDataArr?.some(item => item['ERRORTYPE']);
                        if (hasWarningData) {
                          this.dppMessageService.warning('classification.message.attributeNotFound');
                          return;
                        }
                        modal?.close();
                        this.pasteDataArr.forEach((rule: any) => {
                          if (rule.GUID && rule.GUID.length == 9) {
                            rule.GUID = '';
                          }
                          rule['CODES'] = rule['CODES']?.map((code: any) => {
                            delete code['pasteFieldType'];
                            delete code['pasteTYPEFIXED'];
                            delete code['pasteTypeValue'];
                            delete code['pasteChartSegment'];
                            if (code.GUID && code.GUID.length == 9) {
                              code.GUID = '';
                            }
                            return code;
                          });
                          newParamsRules.push({
                            info: { ...rule },
                            numberFields: rule['CODES']
                          });
                        });
                        this.sysClassificationPasteSynthesisRulesAction(event, newParamsRules);
                        // 更新错误规则数据
                        this.pasteDataArr = [];
                      }
                    }
                  ],
                  width: '80%',
                  height: '70vh'
                },
                {
                  dppRender: render
                }
              );
            }
          );
        } else {
          this.dppMessageService.success('common.operation.pasteSuccess');
        }
        if (successRuleArr?.length) {
          const FIELDNAME = successRuleArr[successRuleArr.length - 1]['FIELDNAME'];
          this.RefreshSynthesisRulesFn(table, rowData, FIELDNAME);
        }
      }
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

