sysSynthesisRulesEditPasteAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const bottom_table = table?.['bottomTable'] as DppTableComponent;
  const rowData = this.getRowData(event) as IFoundaton;

  const triggerCom = table.dppRender.innerSend!.triggerInstance?.() as unknown as DppTableComponent;

  this.setLoading(event, true);
  const dppRender = {
    name: 'sysClassificationAddSynthesisRulesTable',
    mParams: {
      total: false,
      toolbar: 'searchClassToolbar',
      select: 'single',
      dataSource: '/classfication/listRuleFields?classGuid=$classGuid$&classificationGuid=$classificationGuid'
    },
    dParams: {
      classGuid$: triggerCom?.dppRender?.dParams?.['classGuid$'],
      classificationGuid: triggerCom?.dppRender?.dParams?.['guid']
    },
    height: 'calc(100% - 40px)'
  };
  const modal = this.as.openModal(
    {
      title: 'systemSetting.conversion.signatureScheme.command.sysEditTempCommand',
      width: '1000px',
      centered: true,
      canDrag: true,
      content: DppTableComponent,
      bodyStyle: {
        width: 'auto',
        maxWidth: '1000px',
        height: 'calc(100vh - 340px)',
        padding: '20px',
        overflowY: 'scroll'
      },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
            this.setLoading(event, false);
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: (com: DppTableComponent) => {
            // 内容组件
            this.setLoading(event, false);
            const rulesData = com.getCheckedNodeList();
            if (!rulesData?.length) {
              this.dppMessageService.warning('common.operation.noDataSelected');
              return;
            }
            modal?.close();

            const params: any = {
              GUID: `${Math.floor(Math.random() * 1e9)}`,
              CODES: [],
              CLASSGUID: table?.dppRender?.dParams?.['classGuid$'],
              CLASSIFICATIONITEMGUID: table?.dppRender?.dParams?.['guid'],
              FIELDNAME: rulesData[0]?.origin?.['FIELDNAME'],
              FORMAT: rulesData[0]?.origin?.['FORMAT'],
              ISCLASSFIELD: rulesData[0]?.origin?.['ISCLASSFIELD'] || '',
              ISNUMBERING: rulesData[0]?.origin?.['ISNUMBERING'],
              STYLE: rulesData[0]?.origin?.['STYLE'],
              TITLE: rulesData[0]?.origin?.['TITLE']
                ? this.translation.transform(rulesData[0]?.origin?.['TITLE'])
                : null
            };
            this.pasteClickKey = params.GUID;
            this.pasteDataArr = this.pasteDataArr.map(node => {
              if (node['GUID'] == rowData.GUID) {
                node['CODES']?.forEach((item: any) => {
                  item['GUID'] = `${Math.floor(Math.random() * 1e9)}`;
                });
                const nohasWarning = node['CODES'].every((item: any) => !item.message);
                if (nohasWarning) {
                  params['ERRORTYPE'] = '';
                  params['ERROFMESSAGE'] = '';
                } else {
                  params['ERRORTYPE'] = 'PASTE_EXCEPTION';
                  params['ERROFMESSAGE'] = node['ERROFMESSAGE'];
                }
                params['SEGMENTSTYLE'] = node['CODES']?.map((item: any) => `【${item.SEGMENTNAME}】`).join('');
                params['DISPLAYSTYLE'] = node['CODES']
                  .map((item: any) => {
                    if (item.FIELDLENGTH > 0) {
                      return `[${'X'.repeat(Number(item.FIELDLENGTH))}]`;
                    }
                    return '';
                  })
                  .join('');
                return { ...params, IDS: node['IDS'], CODES: node['CODES'] };
              }
              return node;
            });
            let index = this.pasteDataArr.findIndex(item => item.GUID === this.pasteClickKey);
            index = index == -1 ? 0 : index;
            table.dppRender.data = this.pasteDataArr;
            table.refreshData(this.pasteDataArr);
            table.setNodeSelected(index);

            bottom_table.refreshData(this.pasteDataArr[index]['CODES']);
            const dParams = JSON.parse(JSON.stringify(params));
            delete dParams['FIELDNAME'];
