    NAME: 'systemSetting.classification.commonTitle.codeName',
    CODE: 'systemSetting.classification.commonTitle.code',
    TITLE_EN: 'systemSetting.classification.commonTitle.englishTitle',
    TITLE_ZH_CN: 'systemSetting.classification.commonTitle.simplifiedChineseTitle',
    TITLE_ZH_TW: 'systemSetting.classification.commonTitle.traditionalChineseTitle'
  };
  if (rowData['TYPEFIXED'] === 'CODE' && rowData['TYPEVALUE']?.includes('*')) {
    const typeArr = rowData['TYPEVALUE'].split('*');
    last = typeArr?.length > 1 ? typeArr[typeArr.length - 1] : '';
  }

  const render = {
    name: 'sysClassificationAddCodeSegmentForm',
    dParams: { ...rowData, ...parentDate },
    mParams: {
      // expression: 'TYPE:editable=false',
      expression,
      mode: ModeTypeEnum.EDIT,
      isObject: false
    },
    data: {
      // 参数暂时如此
      TYPE: rowData['FIELDTYPE'] ? rowData['FIELDTYPE'] : '',
      TYPE$TITLE: rowData['FIELDTYPE$TITLE'] || '',
      SERIALVALVE: rowData['CODERULEVALUE'] || '',
      SEGMENTNAME: rowData['SEGMENTNAME'] || '',
      LENGTHCOMPENSATE: rowData['LENGTHCOMPENSATE'] || '',
      FIELDNAME: rowData['FIELDNAME'] || '',
      TYPEFIXED: rowData['TYPEFIXED'] || '',
      VALUE: rowData['VALUE'] || '',
      LENGTH: rowData['FIELDLENGTH'] || '',
      TYPEVALUE: last ? last : rowData['TYPEVALUE'] || '',
      TYPEVALUE$TITLE: fieldDescription[last] ? fieldDescription[last] : rowData['TYPEVALUE'] || '',
      PRECODE: rowData['PREFIX'] || '',
      BACKCODE: rowData['SUFFIX'] || ''
    }
  };
  const footer = [
    {
      label: 'common.button.cancel',
      type: 'default',
      onClick: (): void => {
        modal?.close();
      }
    },
    {
      label: 'common.button.save',
      type: 'primary',
      onClick: (formCom: DppFormComponent) => {
        // 内容组件
        const formData = formCom.getNotTranFormData() as IFoundaton;
        if (!formCom.isChanged()) {
          this.dppMessageService.warning('classification.message.dataNotModified');
          return;
        }
        if (formCom.onSubmit()) {
          modal?.close();
          this.setLoading(event, false);
          const flag = this.pasteDataArr?.some(
            item =>
              item?.['SEGMENTNAME'] == formData['SEGMENTNAME'] &&
              item?.['FIELDTYPE'] == formData['TYPE']?.value &&
              item?.['GUID'] != rowData.GUID
          );
          if (flag) {
            this.dppMessageService.warning('classification.message.codeSegmentNameDuplicate');
            return;
          }
          let TYPEVALUE = '';
          if (formData['TYPEVALUE&CODE']) {
            if (formData['TYPEVALUE']?.value && fieldDescription[formData['TYPEVALUE']?.value]) {
              TYPEVALUE = `${formData['TYPEVALUE&CODE']}*${formData['TYPEVALUE']?.value}`;
            } else {
              TYPEVALUE = `${formData['TYPEVALUE&CODE']}`;
            }
          } else if (formData['TYPEFIXED'] === 'CODE') {
            TYPEVALUE = formData['TYPEVALUE']?.value || '';
          } else {
            TYPEVALUE = formData['TYPEVALUE']?.value || formData['TYPEVALUE'] || '';
          }

          let pasteFieldType = formData['TYPE$TITLE'] || '';
          if (formData['pasteFieldType'] && formData['TYPE']?.value === 'field') {
            pasteFieldType = `${formData['TYPE$TITLE']} ${formData['pasteFieldType']}`;
          }

          let pasteChartSegment = '';
          if (formData['FILLPOSITION$TITLE']) {
            pasteChartSegment = `${formData['FILLPOSITION$TITLE']}补${formData['FILLCHARACTER'] ? formData['FILLCHARACTER'] : 0} ${formData['CUTPOSITION$TITLE']}截取`;
          }
          const params = {
            ERROFMESSAGE: '',
            ERRORTYPE: '',
            message: '',
            GUID: `${Math.floor(Math.random() * 1e9)}`,
            title: '',
            key: '',
            pasteFieldType, // 码段类型
            pasteTYPEFIXED: formData['TYPEFIXED'] || '', // 类型值
            pasteTypeValue: formData['TYPEVALUE$TITLE'] || formData['TYPEVALUE'] || '', // 取值
            pasteChartSegment,
            TYPE$TITLE: formData['TYPE$TITLE'],
            FILLPOSITION$TITLE: formData['FILLPOSITION$TITLE'],
            CUTPOSITION$TITLE: formData['CUTPOSITION$TITLE'],
            CLFNUMBERREGULARGUID: table?.dppRender?.dParams?.['classficationFeatureItemguid'],
            CONTROLLED_NUMBERFIELD_GUID: '',
            DATASEQ: '',
            FIELDLENGTH: formData['TYPE']?.value == 'fixed' ? 0 : formData['LENGTH'] || 0,
            FIELDNAME: formData['TYPE']?.value == 'fixed' ? '' : formData['FIELDNAME'] || '',
            SEGMENTNAME: formData['SEGMENTNAME'] || '',
            FIELDTYPE: formData['TYPE']?.value || '',
            ISCLASSFIELD: formData['TYPE']?.value == 'fixed' ? 'N' : formData['ISCLASSFIELD'],
            IS_DATE_BYUSER: '',
            PREFIX: formData['PRECODE'] || '',
            SUFFIX: formData['BACKCODE'] || '',
            TYPEVALUE,
            VALIDATE: formData['VALIDATE'] || '',
            typeFixed: formData['TYPEFIXED'] || '', // 类型值
            CONTROLLEDNUMBERFIELDGUID: formData['CONTROLLEDNUMBERFIELDGUID'] || '', // 流水码的类型值
            FILLPOSITION: formData['FILLPOSITION'],
            FILLCHARACTER: formData['FILLCHARACTER'],
            CUTPOSITION: formData['CUTPOSITION'],
            resutFields: [],
            fieldFroms: formData['fieldFroms']
          };
          // 给组码设置默认值
          if (!formData?.['VALVE']) {
            formData!['VALVE'] = '组码';
          }

          const newData = new Array();
          tableData.forEach(node => {
            if (node['GUID'] == rowData['GUID']) {
              params['IDS'] = node['IDS'];
              node = params;
            }
            newData.push(node);
          });
          table.dppRender.data = newData;
          table.refreshData(newData);

          this.pasteDataArr = this.pasteDataArr.map(item => {
            if (item['GUID'] == table.dppRender.dParams!['GUID']) {
              item['CODES'] = newData;
              const nohasWarning = item['CODES'].every((item: any) => !item.message);
              if (nohasWarning && item['ERRORTYPE'] == 'PASTE_EXCEPTION') {
                item['ERRORTYPE'] = '';
                item['ERROFMESSAGE'] = '';
              }
              item['SEGMENTSTYLE'] = newData.map((item: any) => `【${item.SEGMENTNAME}】`).join('');
              item['DISPLAYSTYLE'] = newData
                .map((item: any) => {
                  if (item.FIELDLENGTH > 0) {
                    return `[${'X'.repeat(Number(item.FIELDLENGTH))}]`;
                  }
                  return '';
                })
                .join('');
            }
            return item;
          });

          let index = this.pasteDataArr.findIndex(item => item.GUID === this.pasteClickKey);
          index = index == -1 ? 0 : index;
          top_table.setNodeSelected(index);
          top_table.dppRender.data = this.pasteDataArr;
          top_table.refreshData(this.pasteDataArr);
        } else {
          this.dppMessageService.warning('classification.message.validationFailed');
        }
      }
    }
  ];
  const modal = this.openCodeSegmentModal(
    event,
    'systemSetting.classification.command.sysEditCodeCommand',
    render,
    footer
  );
}

