// 记录选中数据刷新合成规则
private RefreshSynthesisRulesFn(table: DppTableComponent, rowData: IFoundaton, FIELDNAME?: string): void {
  const bottomTable = table['bottomTable'] as DppTableComponent;
  table.refreshData().subscribe(res => {
    const data = table.getTreeNodes();
    if (res.length > 0) {
      let index = !FIELDNAME ? data.findIndex(item => item.origin['GUID'] === rowData!?.['GUID']) : data.length - 1;
      index = index == -1 ? 0 : index;
      const selectedData = data[index].origin;

      table.setNodeSelected(index!);
      bottomTable.dppRender!.dParams!['classficationFeatureItemguid'] = selectedData['GUID'];
      bottomTable.dppRender!.dParams!['ISINHERIT'] = selectedData['ISINHERIT'];
      bottomTable.topToolbar!.refresh();
      bottomTable?.refreshByParams({
        classficationFeatureItemguid: selectedData['GUID']
      });
    } else {
      bottomTable.dppRender!.dParams!['classficationFeatureItemguid'] = '';
      bottomTable?.refreshByParams({
        classficationFeatureItemguid: ''
      });
    }
  });
}

/**
 * 主表刷新，保持选中并同步详情表
 * 仅用于分类管理-合成规则场景
 */
private refreshKeepSelectionAndSync(masterTable: DppTableComponent, detailTable: DppTableComponent): void {
  const syncDetail = (featureItemGuid: string, isInherit?: unknown): void => {
    const dppRender = detailTable.dppRender!;

    dppRender.dParams!['classficationFeatureItemguid'] = featureItemGuid;
    dppRender.dParams!['ISINHERIT'] = isInherit;
    detailTable.topToolbar?.refresh();
    detailTable.refreshByParams({
      classficationFeatureItemguid: featureItemGuid
    });
  };

  const keepGuid =
    masterTable.getSelectedNodeList()?.[0]?.['origin']?.['GUID'] ??
    detailTable.dppRender!.dParams!['classficationFeatureItemguid'];

  if (!keepGuid) {
    console.warn('未获取到需要保持选中的GUID.将回退至刷新后默认选中首行');
  }

  masterTable.refreshData().subscribe(() => {
    const nodes = masterTable.getAllNodes();
    if (nodes.length === 0) {
      syncDetail('', undefined);
      return;
    }

    const foundIndex = keepGuid ? nodes.findIndex(item => item['origin']?.['GUID'] === keepGuid) : 0;
    const nodeToSelect: RowNode = nodes[foundIndex >= 0 ? foundIndex : 0];

    masterTable.setNodeSelected(nodeToSelect);

    const selectedGuid = nodeToSelect['origin']?.['GUID'];
    if (!selectedGuid) {
      console.error('刷新后未找到有效选中行数据GUID');
      return;
    }

    syncDetail(selectedGuid, nodeToSelect['origin']?.['ISINHERIT']);
  });
}

// 粘贴码段
sysClassificationsPasteCodeSegmentAction(event: EventInterface): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as DppTableComponent;

  if (!table?.dppRender?.dParams?.['classficationFeatureItemguid']) {
    this.dppMessageService.warning('classification.message.missingMergeRule');
    this.setLoading(event, false);
    return;
  }

  const copyCodeSegmentOrigin = this.clipBoardService.getValuesByType(clipBoardTypeEnum.OBJECT_TYPE)!;
  const copyCodeSegment = this.systemConfig.deepCopySet(copyCodeSegmentOrigin) as Set<clipBoardValueType>;
  if (!copyCodeSegment) {
    this.setLoading(event, false);
    this.dppMessageService.warning('classification.message.noCopyObject');
    return;
  }
  const pasteCodeSegmentParams = new Array();
  copyCodeSegment.forEach(item => {
    if (item?.['GUID'] && item?.['SEGMENTNAME']) {
      delete item['GUID'];
      item['ISINHERIT'] = table.dppRender.dParams!['ISINHERIT'];
      pasteCodeSegmentParams.push(item);
    }
  });
  const tableData = table.getTreeNodes();
  if (pasteCodeSegmentParams.length === 0) {
    this.setLoading(event, false);
    // this.dppMessageService.warning('复制集合中不存在码段对象');
    return;
  }
  if (tableData.length + pasteCodeSegmentParams.length > 15) {
    // this.dppMessageService.warning('classification.message.mergeRuleCodeSegmentLimit');
    // return;
  }
  this.systemConfig
    .pasteFeatureItem(
      pasteCodeSegmentParams,
      true,
      table['dppRender']['dParams']?.['classficationFeatureItemguid'],
      table['dppRender']['dParams']?.['classGuid$'],
      table['dppRender']['dParams']?.['guid']
    )
    .subscribe({
      next: res => {
        this.setLoading(event, false);
        if (res.success && res.data) {
          if (res.data['errorCnt']) {
            const errDatas = new Array();
            const errDatas_ = res.data!['details'].filter((i: any) => i.result !== 'SUCCESS');
            errDatas_.map((i: any, index: any) => {
              errDatas.push({
                ...i.data,
                ERRORMESSAGE: i.message,
                ROWCOUNT$: errDatas_.length,
                IDS: index + 1
              });
            });
            this.dppMessageService.customBatchMessage(
              'error',
              {
                actionName: 'classification.message.pasteCodeSegment',
                successCnt: res.data!['successCnt'],
                errorCnt: res.data!['errorCnt'],
                warnCnt: res.data!['errorCnt'],
                totalCnt: res.data!['totalCnt']
              },
              () => {
                const render: IRenderParameterNew<IUiModel> = {
                  name: 'sysClassificationCodeDelErrorTable',
                  mParams: {
                    mode: ModeTypeEnum.EDIT,
                    canSet: 'N',
                    canExport: 'false',
                    canSize: 'N'
                  },
                  data: errDatas as unknown as Record<string, unknown>,
                  dParams: {}
                };
                const modal = this.as.openModal(
                  {
                    title: 'systemSetting.organization.groupManagment.field.failureReason',
                    uiType: 'table',
                    isInteractive: true,
                    footer: 'noFooter',
                    width: '80%',
                    height: '70vh'
                  },
                  {
                    dppRender: render
                  }
                );
              }
            );
          }
          if (res.data['successCnt'] && res.data['successCnt'] === res.data['totalCnt']) {
            this.dppMessageService.success('common.operation.pasteSuccess');
          }
          if (res.data['successCnt']) {
            // 记录选中行刷新顶部表格
            const topTable = table['topTable'] as DppTableComponent;
            this.refreshKeepSelectionAndSync(topTable, table);
          }
        }
      },
      error: err => {
        this.setLoading(event, false);
      }
    });
}

