// 码段修改
sysCodeSegmentEditAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const table = this.getContentCom<DppTableComponent>(event);
  const parentDate = table.dppRender?.dParams;
  const TYPE = ['NAME', 'CODE', 'TITLE_EN', 'TITLE_ZH_CN', 'TITLE_ZH_TW'];
  let expression = false;
  if (TYPE.some(type => rowData['TYPEVALUE'] && rowData['TYPEVALUE'].includes(type))) {
    expression = true;
  }
  if (rowData['TYPEFIXED'] === 'CODE' && rowData['TYPEVALUE']?.includes('*')) {
    // expression = true;
  }
  let last = '';

  const fieldDescription = {
    NAME: 'systemSetting.classification.commonTitle.codeName',
    CODE: 'systemSetting.classification.commonTitle.code',
    TITLE_EN: 'systemSetting.classification.commonTitle.englishTitle',
    TITLE_ZH_CN: 'systemSetting.classification.commonTitle.simplifiedChineseTitle',
    TITLE_ZH_TW: 'systemSetting.classification.commonTitle.traditionalChineseTitle'
  };
  if (rowData['TYPEFIXED'] === 'CODE' && rowData['TYPEVALUE']?.includes('*')) {
    const typeArr = rowData['TYPEVALUE'].split('*');
    last = typeArr?.length > 1 ? typeArr[typeArr.length - 1] : '';
  }

  let TYPEVALUE = '';
  let TYPEVALUE$TITLE = '';
  const getTitle = (v: string): string => fieldDescription?.[v] ?? '';
  if (rowData['FIELDTYPE'] === 'field') {
    TYPEVALUE = last ?? '';
    TYPEVALUE$TITLE = getTitle(last);

    if (!TYPEVALUE && !TYPEVALUE$TITLE && rowData['TYPEFIXED'] === 'CODE') {
      const typeValue = rowData['TYPEVALUE'] ?? '';
      if (getTitle(typeValue)) {
        TYPEVALUE = typeValue;
        TYPEVALUE$TITLE = getTitle(typeValue);
      }
    }
  } else {
    TYPEVALUE = TYPEVALUE$TITLE = rowData['TYPEVALUE'] ?? '';
  }

  const render = {
    name: 'sysClassificationAddCodeSegmentForm',
    dParams: { ...rowData, ...parentDate },
    mParams: {
      // expression: 'TYPE:editable=false',
      expression,
      mode: ModeTypeEnum.EDIT,
      isObject: false
    },
    data: {
      // 参数暂时如此
      TYPE: rowData['FIELDTYPE'] ? rowData['FIELDTYPE'] : '',
      TYPE$TITLE: rowData['FIELDTYPE$TITLE'] || '',
      SERIALVALVE: rowData['CODERULEVALUE'] || '',
      SEGMENTNAME: rowData['SEGMENTNAME'] || '',
      LENGTHCOMPENSATE: rowData['LENGTHCOMPENSATE'] || '',
      FIELDNAME: rowData['FIELDNAME'] || '',
      TYPEFIXED: rowData['TYPEFIXED'] || '',
      VALUE: rowData['VALUE'] || '',
      LENGTH: rowData['FIELDLENGTH'] || '',
      TYPEVALUE: TYPEVALUE,
      TYPEVALUE$TITLE: TYPEVALUE$TITLE,
      PRECODE: rowData['PREFIX'] || '',
      BACKCODE: rowData['SUFFIX'] || ''
    }
  };
  const footer = [
    {
      label: 'common.button.cancel',
      type: 'default',
      onClick: (): void => {
        modal?.close();
      }
    },
    {
      label: 'common.button.save',
      type: 'primary',
      onClick: (formCom: DppFormComponent) => {
        // 内容组件
        const formData = formCom.getNotTranFormData() as IFoundaton;
        // if (!formCom.isChanged()) {
        //   this.dppMessageService.warning('classification.message.dataNotModified');
        //   return;
        // }
        if (formCom.onSubmit()) {
          const tableData = table.getTreeNodes();
          const flag = tableData?.some(
            item =>
              item?.origin?.['SEGMENTNAME'] == formData['SEGMENTNAME'] &&
              item?.origin?.['FIELDTYPE'] == formData['TYPE']?.value &&
              item?.origin?.['GUID'] != rowData.GUID
          );
          if (flag) {
            this.dppMessageService.warning('classification.message.codeSegmentNameDuplicate');
            return;
          }
          let TYPEVALUE = '';
          if (formData['TYPEVALUE&CODE']) {
            if (formData['TYPEVALUE']?.value && fieldDescription[formData['TYPEVALUE']?.value]) {
              TYPEVALUE = `${formData['TYPEVALUE&CODE']}*${formData['TYPEVALUE']?.value}`;
            } else {
              TYPEVALUE = `${formData['TYPEVALUE&CODE']}`;
            }
          } else if (formData['TYPEFIXED'] === 'CODE') {
            TYPEVALUE = formData['TYPEVALUE']?.value || '';
          } else {
            TYPEVALUE = formData['TYPEVALUE']?.value || formData['TYPEVALUE'] || '';
          }
          const params = {
            CLFNUMBERREGULARGUID: table?.dppRender?.dParams?.['classficationFeatureItemguid'],
            CONTROLLED_NUMBERFIELD_GUID: '',
            DATASEQ: '',
            FIELDLENGTH: formData['TYPE']?.value == 'fixed' ? 0 : formData['LENGTH'] || 0,
            FIELDNAME: formData['TYPE']?.value == 'fixed' ? '' : formData['FIELDNAME'] || '',
            SEGMENTNAME: formData['SEGMENTNAME'] || '',
            // FIELDTYPE: formData['FILED$FIELDTYPE'] || '',
            FIELDTYPE: formData['TYPE']?.value || '',
            GUID: rowData?.GUID,
            ISCLASSFIELD: formData['TYPE']?.value == 'fixed' ? 'N' : formData['ISCLASSFIELD'],
            IS_DATE_BYUSER: '',
            PREFIX: formData['PRECODE'] || '',
            SUFFIX: formData['BACKCODE'] || '',
            TYPEVALUE,
            VALIDATE: formData['VALIDATE'] || '',
            typeFixed: formData['TYPEFIXED'] || '', // 类型值
            CONTROLLEDNUMBERFIELDGUID: formData['CONTROLLEDNUMBERFIELDGUID'] || '', // 流水码的类型值
            FILLPOSITION: formData['FILLPOSITION'],
            FILLCHARACTER: formData['FILLCHARACTER'],
            CUTPOSITION: formData['CUTPOSITION'],
            resutFields: [],
            fieldFroms: formData['fieldFroms']
          };
          // 给组码设置默认值
          if (!formData?.['VALVE']) {
            formData!['VALVE'] = '组码';
          }
          this.systemConfig.saveClassNumberField(params).subscribe(res => {
            if (res.success) {
              this.dppMessageService.success('common.operation.operationSuccess');
              const topTable = table['topTable'] as DppTableComponent;
              topTable.refreshData().subscribe(res => {
                const index = topTable
                  .getTreeNodes()
