// 导入规则/码段
sysClassSynthesisRulesImportAction(event: EventInterface, type: boolean): void {
  this.setLoading(event, true);
  const table = this.getContentCom(event) as DppTableComponent;
  const fileInput = document.createElement('input');
  fileInput.type = 'file';
  fileInput.accept = '.csv,.xlsx,.xls';
  fileInput.style.display = 'none';
  fileInput.addEventListener('change', fileEvent => {
    const files = (fileEvent.target as HTMLInputElement).files;
    if (!files || !files[0]) {
      this.dppMessageService.warning('systemSetting.calender.warning.noFilesSelected');
      this.setLoading(event, false);
      return;
    }
    this.systemConfig.importRules(files![0]).subscribe({
      next: res => {
        this.setLoading(event, false);
        if (!res.success || !res.data) {
          return;
        }
        if (res.data!.errorCnt) {
          // this.dppMessageService.createTableMessage('warning', '导入结果', res.data);
          const errDatas = new Array();
          const errDatas_ = res.data!.details.filter(i => i.result !== 'SUCCESS');
          errDatas_.map(i => {
            let tranMess = '';
            if (Array.isArray(i['errorMessage'])) {
              i['errorMessage'].forEach((mess, index, arr) => {
                const tran = this.tranPipe.transform(mess, i.data);
                if (index !== arr.length - 1) {
                  tranMess += `${tran};`;
                } else {
                  tranMess += `${tran}`;
                }
              });
            } else {
              tranMess = this.tranPipe.transform(i['errorMessage'], i.data);
            }
            errDatas.push({ ...i.data, message: tranMess, ROWCOUNT$: errDatas_.length });
          });
          this.dppMessageService.customBatchMessage(
            'error',
            {
              actionName: 'systemSetting.organization.groupManagment.title.import',
              successCnt: res.data!.successCnt,
              errorCnt: res.data!.errorCnt,
              warnCnt: res.data!.errorCnt,
              totalCnt: res.data!.totalCnt
            },
            () => {
              const render: IRenderParameterNew<IUiModel> = {
                name: 'sysClassifyRulesErrTable',
                mParams: {
                  mode: ModeTypeEnum.EDIT,
                  canSet: 'N',
                  canExport: 'false',
                  canSize: 'N',
                  toolbar: 'sysClassifyRulesErrToolbar'
                },
                data: errDatas as unknown as Record<string, unknown>,
                dParams: {}
              };
              const modal = this.as.openModal(
                {
                  title: 'systemSetting.organization.groupManagment.field.failureReason',
                  uiType: 'table',
                  // isInteractive: true,
                  footer: 'noFooter',
                  width: '80%',
                  height: '70vh'
                },
                {
                  dppRender: render
                }
              );
            }
          );
        }
        if (res.data!.successCnt && res.data!.totalCnt === res.data!.successCnt) {
          this.dppMessageService.success('systemSetting.organization.groupManagment.title.importSuccess');
        }
        if (res.data!.successCnt) {
          table.refreshData().subscribe(res => {
            const bottomTable = table['bottomTable'] as DppTableComponent;
            const selectedNode = table.getSelectedNodeList();
            console.log(selectedNode);
            const data = table.getTreeNodes();
            table.setNodeSelected(0);
            bottomTable.dppRender!.dParams!['classficationFeatureItemguid'] = data[0]?.origin?.['GUID'];
            bottomTable.dppRender!.dParams!['ISINHERIT'] = data[0]?.origin?.['ISINHERIT'];
            bottomTable.topToolbar!.refresh();
            bottomTable?.refreshByParams({
              classficationFeatureItemguid: data[0]?.origin?.['GUID']
            });
          });
        }
      },
      error: err => {
        this.setLoading(event, false);
      }
    });
    fileInput.remove();
  });
  fileInput.addEventListener('cancel', fileEvent => {
    fileInput.remove();
    this.setLoading(event, false);
  });
  fileInput.click();
}

