// 保存
sysCodeSaveAction(event: EventInterface): void {
  const form = this.getContentCom(event) as DppFormComponent;
  const origin = form.dppRender.dParams;
  const page = this.getRootPageService(event);
  const itemTable = page.getChildPage('sysCodeItemTableCommand') as DppTableComponent;

  const table = form.dppRender.innerSend?.triggerInstance?.();
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const formData = form.getFormData() as any;
  const isValid = form.onSubmit();
  if (isValid) {
    const params = {
      GUID: formData['GUID'],
      CODENAME: formData['CODENAME'],
      CODETYPE: formData['CODETYPE'],
      DESCRIPTION: formData['DESCRIPTION'],
      TITLE: formData['TITLE'],
      SHOWTYPE: formData['SHOWTYPE'],
      ISCLASSIFICATION: formData['ISCLASSIFICATION']
    };

    const updateCodeHandle = (): void => {
      this.codeManagement.updateCode(params).subscribe({
        next: res => {
          if (res.success) {
            this.dppMessageService.success('common.operation.saveSuccess');
            table.refreshByParams({ ...res.data });
          }
        }
      });
    };

    //CODETYPE List = 2/ Tree = 1
    const result = origin?.['CODETYPE'] === '1' && origin?.['CODETYPE'] !== formData['CODETYPE'];
    if (result) {
      const tip = 'systemSetting.codeManagement.message.codeSaveTips';
      this.as.confirm(tip, {
        title: 'systemSetting.codeManagement.message.pleaseComfirm',
        footer: {
          nzOnOk: () => updateCodeHandle(),
          nzOnCancel: () => { }
        }
      });
      itemTable.refreshData();
    } else {
      updateCodeHandle();
    }
  }
}

// 新增code子项
sysCodeItemNewAction(event: EventInterface): void {
  const tableComponent = event.contentComFn() as unknown as DppTableComponent;
  const dppRender = tableComponent.dppRender;
  const SelectedNodeList = tableComponent.getSelectedNodeList();

  // 1 -> tree/ 2 -> list
  let codeType = dppRender.dParams?.['CODETYPE'];
  let codeName = dppRender?.dParams?.['CODENAME'];
  // 表格行guid
  let masterGuid = dppRender?.dParams?.['GUID'];
  // list时 parentGuid为空;tree不选择行时，parentGuid为空
  let parentGuid = '';

  if (SelectedNodeList && SelectedNodeList.length > 0 && codeType == '1') {
    parentGuid = codeType === '1' ? SelectedNodeList[0]['origin']['GUID'] : '';
    codeName = SelectedNodeList[0]['origin']['ITEMNAME'];
  }
  const formParams: IFormRender = {
    name: FormConfigModelEnum.NEWCODEITEMFORM,
    mParams: {
      mode: ModeTypeEnum.EDIT,
      isObject: false
    },
    data: {
      PARENTITEM: codeName,
      CODETYPE: dppRender?.dParams?.['CODETYPE']
    }
  };
  const modal = this.as.openModal(
    {
      title: 'systemSetting.codeManagement.commonTitle.newItem',
      width: '600px',
      height: 'auto',
      closable: true,
      openModalCloseDrawer: false,
      content: DppFormComponent,
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: formCpn => {
            modal.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: formCpn => {
            const isValid = formCpn.onSubmit();
            const formData = formCpn.getFormData();
            // console.log('d', formData);
            formData['MASTERGUID'] = masterGuid;
            formData['PARENTGUID'] = parentGuid;

            if (isValid) {
              formCpn.setLoading(true);
              this.codeManagement.updateCodeItem(formData).subscribe({
                next: res => {
                  formCpn.setLoading(false);
                  if (res.success) {
                    this.dppMessageService.success('common.operation.newSuccess');

                    // 判断是否添加到根上，还是添加到子上
                    const addToRoot = parentGuid === '';
                    if (addToRoot) {
                      tableComponent.applyTransaction({
                        add: [res.data]
                      });
                    } else {
                      const selectNode = SelectedNodeList[0];
                      const path = this.getRoute(selectNode);
                      tableComponent.applyTransaction({
                        add: [res.data],
                        route: path
                      });
                      selectNode.isExpanded = true;
                    }
                    modal.close();
                  }
