    const menuCom = rootPage.getComFnMapByName('sysConfigurationTransformationLeftMenuCommand') as DppMenuComponent
    const selectNode = menuCom.getSelectedData()?.data
    const key = selectNode?.key
    const guid = selectNode['origin']?.GUID$
    const formParams: IFormRender = {
        name: 'sysNewTransferForm',
        mParams: { mode: ModeTypeEnum.EDIT, isObject: false },
        dParams: { key, guid }
    }
    // eslint-disable-next-line @typescript-eslint/no-this-alias
    const that = this
    const modal = this.as.openModal(
        {
            title: 'systemSetting.conversion.convertSetting.command.AddConvertCommand',
            width: '800px',
            height: '400px',
            closable: true,
            content: DppFormComponent,
            openModalCloseDrawer: false,
            footer: [
                {
                    label: 'common.button.cancel',
                    type: 'default',
                    onClick: formCpn => {
                        formCpn.reset()
                        modal.close()
                    }
                },
                {
                    label: 'common.button.confirm',
                    type: 'primary',
                    onClick(formCpn) {
                        this.loading = true
                        let isValid = formCpn.onSubmit()
                        const formData = formCpn.getFormData()
                        formData.TARGET = formData.TARGET?.value ?? formData.TARGET
                        formData.WORKFLOWACTRTS = that.WORKFLOWACTRTS
                        if (
                            (formData.CLASSIFICATION$TITLE === '流程触发' || formData.CLASSIFICATION$NAME === 'Workflow') &&
                            !that.WORKFLOWACTRTS[0]
                        ) {
                            that.dppMessageService.info(
                                'systemSetting.conversion.convertSetting.warning.workflowConfigurationNull'
                            )
                            isValid = false
                        }
                        formData.FIELDMAPPINGLIST = that.FIELDMAPPINGLIST
                        if (
                            (formData.TARGET$TITLE === '对象' || formData?.TARGET$NAME === 'Object') &&
                            !that.FIELDMAPPINGLIST[0]
                        ) {
                            that.dppMessageService.info('systemSetting.conversion.convertSetting.warning.convertObjectNull')
                            isValid = false
                        }

                        if (isValid) {
                            that.configurationTransformationService.addTransfer(formData).subscribe({
