                maxHeight: '700px',
                borderRadius: '5px',
                overflowY: 'auto',
                padding: '10px'
            },
            triggerInstance: () => this.getContentCom(event),
            reFreshCallBack: () => {
                modal?.close()
            },
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
