                    type: 'default',
                    onClick: () => {
                        modal.close()
                    }
                },
                {
                    label: 'common.button.confirm',
                    type: 'primary',
                    onClick(res: any) {
                        this.loading = true
                        const docTemplates: Array<{ GUID$: string; CLASSGUID$: string }> = []
                        const rootPage = that.getRootPageService(event)
                        const menuCom = rootPage.getComFnMapByName('sysSignatureSchemeMenuCommand') as DppMenuComponent
                        const signatureSchemeGuid = menuCom.getSelectedData()?.data?.['value']!
                        if (res.getCheckedNodes()?.length) {
