                                docTemplates.push({
                                    GUID$: item.origin?.GUID$,
                                    CLASSGUID$: item.origin?.CLASSGUID$
                                })
                            })
                            that.configurationTransformationService
                                .addSignatureTemplate(signatureSchemeGuid, docTemplates)
                                .subscribe({
                                    next: requestRes => {
                                        if (requestRes.success) {
                                            requestRes.data.details.forEach(
                                                (item: { data: { MESSAGE$: string }; message: string; result: string }) => {
                                                    if (item.result === 'SUCCESS' && item.data.MESSAGE$) {
                                                        that.dppMessageService.info(item.data.MESSAGE$)
                                                    }
                                                }
                                            )
                                            if (requestRes.data?.successCnt && requestRes.data?.successCnt === requestRes.data?.totalCnt) {
                                                that.dppMessageService.success('common.operation.operationSuccess')
                                            } else {
                                                that.errorMessageService.showMessage(event, requestRes)
                                            }
                                            this.loading = false
                                            modal.close()
                                            requestRes.data?.successCnt ? table.refreshData() : ''
                                        }
                                    },
                                    error: err => {
                                        this.loading = false
                                    }
                                })
                        } else {
                            that.dppMessageService.warning('common.operation.noDataSelected')
                            this.loading = false
                        }
                    }
                }
            ]
        },
        {
            dppRender: {
                ...action,
                dataSource: `/transformConfigurate/listDocumentTemplate`,
                name: 'sysAddSignatureSchemeTable'
            }
        }
    )
}

