        [tableData[index - 1], tableData[index]] = [tableData[index], tableData[index - 1]]
        table.refreshData(tableData as unknown as RowNode)
    }
}

// 下移
sysCompositeFieldMovedownAction(event: EventInterface): void {
    const tableData = this.getData(event) as IBaseData[]
    const currentId = this.getRowData(event)['ID']
    const table = this.getContentCom(event) as unknown as DppTableComponent
    const index = tableData.findIndex(item => item['ID'] === currentId)
    if (index < tableData.length - 1) {
        [tableData[index], tableData[index + 1]] = [tableData[index + 1], tableData[index]]
        table.refreshData(tableData as unknown as RowNode)
    }
}

