// 转换配置保存
sysConfigurationTransformationSaveAction(event: EventInterface): void {
    const tableCpnData = this.getContentCom(event) as DppTableComponent
    const triggerInstance = (tableCpnData.dppRender.innerSend as any)['triggerInstance']()
    const form = this.getAppointPage(event, 'sysTransferDrawerCommand') as unknown as DppFormComponent
    let isValid = form.onSubmit()
    const formData = form.getFormData() as any
    // if(formData['TRANSORIGINCLASSFN$NODES']) {
    //   formData.TRANSORIGINCLASSFN = formData['TRANSORIGINCLASSFN$NODES'][0].key
    // }
    formData.WORKFLOWACTRTS = this.WORKFLOWACTRTS
    if (
        (formData.CLASSIFICATION$TITLE === '流程触发' ||
            formData.CLASSIFICATION$TITLE === 'Workflow Trigger;流程触发;流程觸發') &&
        !this.WORKFLOWACTRTS?.[0]
    ) {
        this.dppMessageService.info('流程配置不能为空!')
        isValid = false
    }
    formData.FIELDMAPPINGLIST = this.FIELDMAPPINGLIST
    if (
        (formData.TARGET$TITLE === '对象' || formData?.TARGET$TITLE === 'Object;对象;對象') &&
        !this.FIELDMAPPINGLIST?.[0]
    ) {
        this.dppMessageService.info('转换对象不能为空!')
        isValid = false
    }
    if (isValid) {
        this.configurationTransformationService
            .addTransfer({
                ...formData,
                GUID$: formData['GUID'],
                WORKFLOWACTRTS: this.WORKFLOWACTRTS,
                FIELDMAPPINGLIST: this.FIELDMAPPINGLIST
            })
            .subscribe(res => {
                if (res.success) {
                    this.dppMessageService.success('common.operation.operationSuccess')
                    triggerInstance.refreshByParams({})
                    this.TransferDrawer.close()
                }
            })
    }
}

