// 主文件下载
downloadMainFileAction(event: any): void {
    const fileInstance = event.exeComFn()
    const rowData = event.exeComFn().node.origin
    const file = event.data
    fileInstance.cdr.detectChanges()
    let fileName = file.fileName
    let isAll = false
    if (rowData.OBJECTTYPE$ === '3DCad' && rowData.MODELCLASS$NAME === 'asm') {
        fileName = fileName.replace(/\.([^.]*)$/, '.zip')
        isAll = true
    }
    this.downloadFile(file, fileName, isAll)
}

downloadFile(file: any, fileName: string, isAll: boolean): void {
    const getFile$ = this.configurationTransformationService.downloadAllFile
    const param = `false/${file.fileGuid}`
    file.loading = true
    getFile$.call(this.configurationTransformationService, param, isAll).subscribe({
        next: res => {
            if (window.navigator && window.navigator['msSaveOrOpenBlob']) {
                window.navigator['msSaveOrOpenBlob'](res.data!, fileName)
            } else {
                const url = window.URL.createObjectURL(res.data!)
                const a = document.createElement('a')
                a.href = url
                a.download = fileName
                document.body.appendChild(a)
                a.click()
                document.body.removeChild(a)
                window.URL.revokeObjectURL(url)
            }
            file.loading = false
        },
        error: err => {
            file.loading = false
        }
    })
}

