// 处理可用对象
handleAvailableObject(
  field: any,
  observer: Observer<CustObjectOpenRet>,
  config: { wfName: string; targetKey: string }
): void {
  if (!config.wfName) {
    this.dppMessageService.warning('systemSetting.workflowTemplate.message.warning.selectTemplateFirst');
    return;
  }
