// 选择对象及分类(可发起对象)
handleLaunchObject(
  field: any,
  formCpn: DppFormComponent,
  observer: Observer<CustObjectOpenRet>,
  config: { wfName: string; targetKey: string }
): void {
  let existLaunchObject = field['tags'];
  let availScopeBoList: Array<{ BOGUID: string; CLASSIFICATION: string }> = [];

  const AVAILABLE_SCOPE = formCpn['data']['AVAILABLE_SCOPE'] as Array<{
    title: string;
    origin: Record<string, string>;
  }>;
  console.log(AVAILABLE_SCOPE);

  if (AVAILABLE_SCOPE && AVAILABLE_SCOPE.length > 0) {
    AVAILABLE_SCOPE.forEach(item => {
      availScopeBoList.push({
        BOGUID: item.origin['BOGUID'],
        CLASSIFICATION: item.origin['CLASSIFICATION']
      });
      // availBoGuidList.push(item.origin['BOGUID']);
    });
  }

  availScopeBoList = Array.from(new Set(availScopeBoList.map(obj => JSON.stringify(obj)))).map(str =>
    JSON.parse(str)
  );

  this.wfTemplateService.listLaunchBoTree({ wfName: config.wfName, availScopeBoList: availScopeBoList }).subscribe({
    next: res => {
      const modal = this.as.openModal(
        {
          title: 'systemSetting.workflowTemplate.command.selectLaunchableObjects',
          width: '70%',
          bodyStyle: {
            height: '500px'
          },
          openModalCloseDrawer: false,
          content: ClassficationSelectComponent,
          footer: [
            {
              label: 'common.button.cancel',
              type: 'default',
              onClick: () => {
                modal.close();
              }
            },
            {
              label: 'common.button.confirm',
              type: 'primary',
              onClick: (classCpn: ClassficationSelectComponent) => {
                const selectedData = classCpn.table.getTreeNodes();
                // const selectedData = classCpn.table.getCheckedNodes();
                let params: CustObjectItem[] = [];
                if (!selectedData.length) {
                  this.dppMessageService.warning('common.operation.noDataSelected');
                }
                selectedData.forEach(item => {
                  item.origin['BOTITLE'] = this.dpptranslate.transform(item.origin['BOTITLE']);
                  item.origin['CFTITLE'] = this.dpptranslate.transform(item.origin['CFTITLE']);

                  const title =
                    item.origin['TYPE'] === 'CLASSIFICATION'
                      ? `${this.dpptranslate.transform(item.origin['BOTITLE'])}-${this.dpptranslate.transform(item.origin['CFTITLE'])}`
                      : this.dpptranslate.transform(item.origin['BOTITLE']);
                  params.push({
                    title: title,
                    origin: item.origin
                  });

                  if (!params.length) {
                    this.dppMessageService.warning('common.operation.noDataSelected');
                  }

                  if (params.length > 0) {
                    observer.next({
                      // filterKey: 'GUID',
                      items: params
                    });
                    modal.close();
                  }
                });
              }
            }
          ]
        },
        {
          dppRender: {
            dParams: {
              wfName: config.wfName,
              newCheckedKeys: CustomizeFormUtils.collectTreeGuids(existLaunchObject, res.data!)
            },
            mParams: {
              checkable: true
            },
            data: res.data
          }
        }
      );
    }
  });
}

