setAgentOpen: CustomObjectOpenFn = (field, formCpm) => {
  return new Observable<CustObjectOpenRet>(observer => {
    const data = (
      field.formControl.value && field.formControl.value.length > 0 ? field.formControl.value[0].origin : {}
    ) as IAgent;
    const render: IFormRender = {
      name: 'sysOrganAgentForm',
      mParams: {
        mode: ModeTypeEnum.EDIT
      },
      data: data as unknown as Record<string, unknown>
    };
    const user = formCpm.getFormData<IUser>();
    if (isEmpty(render.data) && user.GUID) {
      render.data = {
        PRINCIPAL: user.GUID,
        PRINCIPAL$NAME: user.USERNAME,
        PRINCIPAL$ID: user.USERID
      };
    }
    render.data!['isSetAgent'] = 'Y';
    // 自定义操作
    const modal = this.as.openModal(
      {
        title: 'systemSetting.organization.orgzManagement.command.setAgent',
        height: '400px',
        width: '30%',
        openModalCloseDrawer: false,
        footer: [
          {
            label: 'common.button.close',
            onClick: (formCpm: DppFormComponent) => {
              modal.close();
            }
          },
          {
            label: 'common.button.save',
            type: 'primary',
            onClick: (formCpm: DppFormComponent) => {
              if (!formCpm.onSubmit()) {
                return;
              }
              const agent = formCpm.getFormData<IAgent>();
              agent.AGENTGUID = agent.AGENT;
              agent.AGENTNAME = agent.AGENT$NAME;
              agent.PRINCIPALGUID = agent.PRINCIPAL;
              agent.PRINCIPALNAME = agent.PRINCIPAL$NAME;
              agent.STARTDATE = agent.PROXYINTERVAL[0];
              agent.FINISHDATE = agent.PROXYINTERVAL[1];
              agent.ACTIVE$TITLE =
                agent.ACTIVE === 'Y'
                  ? 'systemSetting.organization.orgzManagement.field.valid'
                  : 'systemSetting.organization.orgzManagement.field.invalid';

              if (agent.PRINCIPAL === agent.AGENT) {
                this.dppMessageService.warning('systemSetting.organization.userManagment.warning.samePerson');
                return;
              }
              if (new Date(agent.FINISHDATE) <= new Date(agent.STARTDATE)) {
                this.dppMessageService.warning(
                  'systemSetting.organization.userManagment.warning.startDateCannotLaterEndDate'
                );
                return;
              }
              observer.next({
                items: [
                  {
                    title: `${agent.AGENT$NAME}(${agent.ACTIVE === 'Y' ? '生效' : '不生效'}) ${agent.PROXYINTERVAL[0]}~${agent.PROXYINTERVAL[1]}`,
                    origin: agent
                  }
                ]
              });
              observer.complete();
              modal.close();
            }
          }
        ],
        uiType: 'form'
      },
      { dppRender: render }
    );
  }).pipe(
    catchError(error => {
      throw error;
    })
  );
};

