  if (config) {
    const params = Object.entries(config.mapping).reduce((acc, [targetKey, sourceKey]) => {
      acc[targetKey] = getValueByPriority(value, sourceKey);
      return acc;
    }, {} as any);
    return of(params);
  }
  return of({} as any);
