  const bs = this.getExeCom<DppButtonComponent>(event);
  this.setLoading(event, true);
  const component = this.getContentCom(event) as DingdingIntegratedComponent; // 表格组件
  const formComponent = component.dingdingIntegratedFormComponent;
  const isValid = formComponent.onSubmit();
  if (isValid) {
    const formData = formComponent.getFormData() as NzSafeAny;
    // console.log('formData', formData);
    let object: {
      AGENTID: string;
      MINIAPPID: string;
      APPKEY: string;
      APPSECRET: string;
      CORPID: string;
      SELECTNAME: string;
      SYNMESSAGE: string;
    } = {
      AGENTID: formData['AGENTID'],
      MINIAPPID: formData['MINIAPPID'],
      APPKEY: formData['APPKEY'],
      APPSECRET: formData['APPSECRET'],
      CORPID: formData['CORPID'],
      SELECTNAME: formData['SELECTNAME'],
      SYNMESSAGE: formData['SYNMESSAGE']
    };

    this.dingdingIntegratedService.saveIntegration(object).subscribe({
