 * @param event
 */
sysERPIntegratedTemplateCopyAndAddAction(event: EventInterface): void {
  const tableCom = this.getContentCom(event);
  const currentSelectCard = tableCom?.['modelManager']?.['_dppRender']?.['dParams']?.['currentSelectCard'];
  const rowData = this.getRowData(event);
  const ISINUSE = rowData['ISINUSE'] == 'Y' ? '1' : '';
  const ISPRIORITY = rowData['ISPRIORITY'] == 'Y' ? '0' : '';
  const moreCompanyList = rowData['MORECOMPANYLIST'];
  const moreCompanyTitle = rowData['MORECOMPANYLIST$TITLE'];
  let moreCompanyData: Array<{
    label?: string;
    value?: string;
  }> = [];
  for (let i in moreCompanyList) {
    moreCompanyData.push({
      value: moreCompanyList[i],
      label: moreCompanyTitle[i]
    });
  }
  const successfulNotifiacionList = rowData['ENDNOTICEPERSONLIST'];
  const successfulNotifiacionTitles = rowData['ENDNOTICEPERSONLIST$TITLE'];
  const successfulNotifiacionTypes = rowData['ENDNOTICEPERSONLIST$TYPE'];
  let successfulNotifiacion: Array<{
    guid?: string;
    id?: string;
    name?: string;
    label?: string;
    value?: string;
    type?: string;
  }> = [];
  for (let i in successfulNotifiacionList) {
    // console.log(successfulNotifiacionList[i]);
    successfulNotifiacion.push({
