// 新建里程碑
sysMilestoneLeftNewCreateAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const tableData = table.getTreeNodes();
  const modal = this.as.openModal(
    {
      title: 'systemSetting.projectMessageRule.title.newProjectType',
      width: '480px',
      content: DppFormComponent,
      bodyStyle: { height: '200px', padding: '0 10px 0 0' },
      footer: [
        {
          label: 'common.button.cancel',
          type: 'default',
          onClick: (): void => {
            modal?.close();
          }
        },
        {
          label: 'common.button.confirm',
          type: 'primary',
          onClick: data => {
            // 内容组件
            const isValid = data.onSubmit();
            const formData = data.getFormData();
            const hasAsName = tableData.some(item => item.origin['name'] === formData.TYPEGUID);
            if (hasAsName) {
              this.dppMessageService.create('warning', 'systemSetting.milestone.milestoneTypeDup');
              return;
            }
            if (isValid) {
              data.setLoading(true);
              this.systemConfig.saveMilestone({ remark: formData.DESCRIPTION, name: formData.TYPEGUID }).subscribe({
                next: res => {
                  if (res.success) {
                    this.dppMessageService.create('success', 'common.operation.newSuccess');
                    table?.['milestoneCard'].setDppRender({ ...res.data, checkPointNum: formData.CHECKPOINTNUM });
                    table?.refreshData().subscribe(res => {
                      table.setNodeSelected(0);
                    });
                  }
                  data.setLoading(false);
                  modal?.close();
                },
                error: err => data.setLoading(false)
              });
            }
          }
        }
      ],
      canDrag: true
    },
    {
      dppRender: {
        name: 'tempSysNewMilestoneForm',
        mode: ModeTypeEnum.EDIT
      }
    }
  );
}

// 里程碑类型编辑
sysMilestoneTypeEditAction(event: CellSaveEvent): Observable<DppSafeAny> {
  const table = event.beans.table;
  const tableData = table.getTreeNodes();
  const rowData = event.data;
  const params = {
    guid: rowData['guid'],
    name: rowData['name'],
    remark: rowData['remark']
  };
  let hasAsName = 0;
  tableData.forEach(item => {
    if (item.origin['name'] === rowData['name']) {
      hasAsName++;
    }
  });
  if (hasAsName > 1) {
    this.dppMessageService.create('warning', 'systemSetting.milestone.milestoneTypeDup');
    table.refreshData();
    return of(false);
  }
  return new Observable(observer => {
    this.systemConfig.saveMilestone(params).subscribe(
      res => {
        if (res.success && res.data) {
          const tableRes = {
            success: true,
            data: rowData
          };
          observer.next(tableRes);
          this.dppMessageService.success('common.operation.operationSuccess');
        }
      },
      error => {
        observer.error({
          success: false
        });
      }
    );
  });
}

