// 删除里程碑类型
sysdeleteMilestoneAction(event: EventInterface): void {
  const table = this.getContentCom(event) as DppTableComponent;
  const node = this.getNode(event) as RowNode;
  const data = table.getTreeNodes();
  const index = data.findIndex((item: RowNode) => item.origin['guid'] === node.origin?.['guid']);
  let nextInx: number | null;
  if (data?.length !== 1) {
    if (index === data.length - 1) {
      nextInx = 0;
    } else {
      nextInx = index + 1;
    }
  } else {
    nextInx = null;
  }
  this.systemConfig.deleteMilestone(node.origin?.['guid']).subscribe(res => {
    if (res.data && res.success) {
      this.dppMessageService.create('success', 'common.operation.deleteSuccess');
      if (nextInx !== null) {
        table['milestoneCard'].setDppRender(data[nextInx]?.origin);
      } else {
        table['milestoneCard'].setDppRender({});
      }
      table?.refreshData()?.subscribe(res => {
        if (res && nextInx !== null) {
          table.setSelectedNext(node);
        }
      });
    }
  });
}

