/**
 * @ToQY
 * @use 用户页面 - 保存按钮，用户编辑/新建抽屉底部"保存"按钮点击时触发
 * @type 通用事件接口
 */
sysOrgantUserSaveAction(event: EventInterface): void {

    const formCpm = this.formRootFindChild<DppFormComponent>(event, CommandConstant.OrgantUserTop)!
    if (!formCpm.onSubmit()) {
        return
    }
    const tranUser = formCpm.getFormData<IUser>() as IUser & Partial<FormFileProp>
    const isEdit = formCpm.dppRender.dParams!['isEdit']
    const user = deepCopy(tranUser) as IUser & Partial<FormFileProp>
    if (user.AGENT && user.AGENT.length > 0) {
        user.AGENT = user.AGENT[0].origin as any
    } else {
        user.AGENT = null as any
    }
    user.DWFILES = tranUser.DWFILES
    user.FILEPROPS$ = tranUser.FILEPROPS$

    this.setLoading(event, true)
    this.organService.saveUser(user).subscribe({
        next: res => {
            this.setLoading(event, false)
            if (!res.success) {
                return
            }
            // this.messageService.success('');
            this.getTriggerDrawer(event)?.close()
            const table = this.getTrigger<DppTableComponent>(event)
            if (isEdit === 'Y') {
                const nodes = table.getAllNodes()
                const findNode = nodes.find(node => node.origin['GUID'] === user.GUID)
                if (findNode) {
                    const newData = deepCopy(findNode.origin)
                    Object.assign(newData, user)
                    Object.assign(newData, res.data)
                    findNode.setData(newData)
                }
            } else {
                table.refreshData()
            }
        },
        error: err => this.setLoading(event, false)
    })
}

