    const formCpm = this.formRootFindChild<DppFormComponent>(event, CommandConstant.OrgantUserTop)!
    if (!formCpm.onSubmit()) {
        return
    }
    const user = formCpm.getFormData<IUser>()
    this.setLoading(event, true)
    if (user.AGENT && user.AGENT.length > 0) {
        user.AGENT = user.AGENT[0].origin as DppSafeAny
    } else {
        user.AGENT = null as DppSafeAny
    }
    this.organService.saveUser(user).subscribe({
        next: res => {
            this.setLoading(event, false)
            if (!res.success) {
                return
            }
            res.data!.USERID = ''
            res.data!.USERNAME = ''
            res.data!.GUID$ = ''
            res.data!.GUID = ''
            formCpm.callback({
                action: EventCallbacksActionName.UPDATE,
                params: res.data
            })
            this.getTrigger<DppTableComponent>(event).refreshData()
        },
        error: err => this.setLoading(event, false)
    })
}

