 * @type Tag删除事件
 */
rigDelTagAction(event: TagDeleteEvent): void {
    const data = event.node.origin
    const guid = data['GUID']
    const rig = event.removeTag.origin.origin as IRig

    const content = this.tranPipe.transform('systemSetting.organization.userManagment.warning.delRig')
    const title = 'common.operation.confirm.CheckIn.title'

    this.as.confirm({
        content,
        title,
        footer: {
            onOk: () => {
                this.organService.removeUserToRig(guid, rig).subscribe({
                    next: res => {
                        if (!res.success) {
                            return
                        }

                        const table = event.beans.table
                        const page = table.dppRender.innerSend?.getPageThis?.()
                        if (!page) {
                            event.deleteTagAndRefreshCell()
                            return
                        }

                        const leftMenu = page.getChildPage(CommandConstant.OrganSMenu) as DppMenuComponent
                        const currentNode = leftMenu.getSelectedData()?.data
