/**
 * @use 组织管理表格 - 用户生失效切换，组织管理模块表格单元格中用户状态Switch切换时触发
 * @type Switch切换事件
 */
sysOrganActiveAction(event: SwitchChangeEvent): void {
    const { newValue, data, node: tableNode, setLoading } = event
    const guid = data.GUID
    const agent = data.AGENT

    // 执行生效失效最终接口
    const applyChange = (close?: () => void, resData?: IUser): void => {
        this.organService.reverseUserState(data, newValue).subscribe({
            next: res => {
                setLoading(false)
                if (!res.success) {
                    return
                }
                if (close) {
                    close()
                }
                if (res.data) {
                    tableNode.setData(res.data)
                }
                tableNode.setDataValue(event.column.key, newValue)
            },
            error: err => {
                event.setLoading(false)
            }
        })
    }

    const openModal = (confirm: () => void, cancel: () => void): void => {
        const content = 'systemSetting.organization.userManagment.warning.invalid'
        const title = 'common.operation.confirm.CheckIn.title'
        this.as.confirm({
            content,
            title,
            onOk: confirm,
            onCancel: cancel
        }, { name: data.USERNAME })
    }

    //失效判断
    // step1 判断是否有未完成的工作流
    // step2 判断代理��是否在生效期间 不在则重新设置代理人
    const applyWorkflowLapse = (): void => {
        this.workFlowService.hasIncompleteWorkflow(guid).subscribe({
            next: res => {
                if (!res.success) {
                    setLoading(false)
                    return
                }

                if (!res.data) {
                    openModal(applyChange, () => {
                        setLoading(false)
                    })
                    return
                }

                if (agent && agent.length > 0) {
                    if (
                        agent[0].origin.ACTIVE === 'Y' &&
                        OrganizationEventUtil.isDateInRange(
                            new Date(),
                            new Date(agent[0].origin.STARTDATE),
                            new Date(agent[0].origin.FINISHDATE)
                        )
                    ) {
                        openModal(applyChange, () => {
                            setLoading(false)
                        })
                    } else {
                        this.organActiveAgentConfirm(
                            () => {
                                setLoading(false)
                            },
                            applyChange,
                            data
                        )
                    }
                } else {
                    this.organActiveAgentConfirm(
                        () => {
                            setLoading(false)
                        },
                        applyChange,
                        data
                    )
                }
            },
            error: err => {
                setLoading(false)
            }
        })
    }

    if (newValue === 'Y') {
        applyChange()
    } else {
        applyWorkflowLapse()
    }
}

