/**
 * @use 私有方法 - 确认失效代理人设置，用户失效时确认代理人设置
 */
private organActiveAgentConfirm(
    closeLoading: () => void,
    applyChange: (closeModel: () => void, resData?: IUser) => void,
    user: IUser
): void {
    this.as.openModal<AgentConfirmComponent>(
        {
            title: 'common.operation.confirm.CheckIn.title',
            uiType: 'agent-confirm',
            width: '40%',
            height: '400px',
            footer: [
                {
                    label: 'common.button.cancel',
                    type: 'default',
                    onClick: ctx => {
                        ctx.close()
                        closeLoading()
                    }
                },
                {
                    label: 'common.button.confirm',
                    type: 'primary',
                    onClick: ctx => {
                        const confitmFormCpm = ctx.getComponent() as any
                        if (!confitmFormCpm.formCpm.onSubmit()) {
                            return
                        }


                        const agent = confitmFormCpm.formCpm.getFormData()
                        // const agent1 = formCpm.getNotTranFormData<IAgent>();
                        agent.AGENTGUID = agent.AGENT
                        agent.AGENTNAME = agent.AGENT$NAME
                        agent.PRINCIPALGUID = agent.PRINCIPAL
                        agent.PRINCIPALNAME = agent.PRINCIPAL$NAME
                        agent.STARTDATE = agent.PROXYINTERVAL[0]
                        agent.FINISHDATE = agent.PROXYINTERVAL[1]
                        if (agent.PRINCIPAL === agent.AGENT) {
                            this.messageService.warning('systemSetting.organization.userManagment.warning.samePerson')
                            return
                        }
                        if (
                            !OrganizationEventUtil.isDateInRange(new Date(), new Date(agent.STARTDATE), new Date(agent.FINISHDATE))
                        ) {
                            this.messageService.warning('systemSetting.organization.userManagment.warning.notInAgentTimes')
                            return
                        }
                        ctx.button.setLoading(true)
                        this.organService.reverseUserAgent(agent).subscribe({
                            next: res => {
                                if (!res.success) {
                                    ctx.button.setLoading(false)
                                    return
                                }
                                applyChange(() => {
                                    ctx.close()
                                }, res.data!)
                            },
                            error: err => {
                                ctx.button.setLoading(false)
                                closeLoading()
                            }
                        })
                    }
                }
            ],
            afterClose: () => {
                closeLoading()
            }
        },
        {
            user: deepCopy(user)
        }
    )

}

