 * @use 组织管理表格 - Toolbar搜索，组织管理模块表格顶部搜索框输入时触发
 * @type 表格顶部工具栏执行事件
 */
sysOrgantSearchAction(event: TableTopToolbarExecuteEvent): void {
    const { btnApi, tableApi } = event

    const value = btnApi.getValue()


    const searchCondition = new QueryCondition(DppQueryConditionOperator.OR)

    const operator = DppQueryConditionOperator.LIKE

    searchCondition.addCondition(new QueryConditionInfo('USERID', [value], operator))
    searchCondition.addCondition(new QueryConditionInfo('TEL', [value], operator))
    searchCondition.addCondition(new QueryConditionInfo('MOBILE', [value], operator))
    searchCondition.addCondition(new QueryConditionInfo('USERNAME', [value], operator))

    tableApi.refreshByCondition(searchCondition)
}

