sysOrgantSetAgentAction(event: TableCellToolbarExecuteEvent): void {
    const { data, btnApi, node: tableNode } = event

    const userData = data as IUser

    const formData = isEmpty(userData.AGENT)
        ? {
            PRINCIPAL: userData.GUID$,
            PRINCIPAL$ID: userData.USERID,
            PRINCIPAL$NAME: userData.USERNAME
        }
        : userData.AGENT[0].origin

    formData['isSetAgent'] = 'Y'
    const render: IFormRender = {
        name: 'sysOrganAgentForm',
        mParams: {
            mode: ModeTypeEnum.EDIT
        },
        data: formData as unknown as Record<string, unknown>
    }

    this.as.openModal<FormApi>(
        {
            title: btnApi.getModel().label,
            height: '400px',
            width: '30%',
            openModalCloseDrawer: false,
            footer: [
                {
                    label: 'common.button.close',
                    onClick: ctx => {
                        ctx.close()
                    }
                },
                {
                    label: 'common.button.save',
                    type: 'primary',
                    onClick: ctx => {
                        const formCpm = ctx.getContentApi()

                        if (!formCpm.onSubmit()) {
                            return
                        }
                        const agent = formCpm.getFormData<IAgent>()

                        agent.AGENTGUID = agent.AGENT
                        agent.AGENTNAME = agent.AGENT$NAME
                        agent.PRINCIPALGUID = agent.PRINCIPAL
                        agent.PRINCIPALNAME = agent.PRINCIPAL$NAME
                        agent.STARTDATE = agent.PROXYINTERVAL[0]
                        agent.FINISHDATE = agent.PROXYINTERVAL[1]

                        if (agent.PRINCIPAL === agent.AGENT) {
                            this.messageService.warning('systemSetting.organization.userManagment.warning.samePerson')
                            return
                        }
                        if (new Date(agent.FINISHDATE) <= new Date(agent.STARTDATE)) {
                            this.messageService.warning(
                                'systemSetting.organization.userManagment.warning.startDateCannotLaterEndDate'
                            )
                            return
                        }

                        btnApi.setLoading(true)

                        this.organService.reverseUserAgent(agent).subscribe({
                            next: res => {
                                btnApi.setLoading(false)
                                if (!res.success) {
                                    return
                                }

                                tableNode.setData(res.data)
                                ctx.close()
                            },
                            error: err => btnApi.setLoading(false)
                        })
                    }
                }
            ],
            uiType: 'form',
            params: {
                dppRender: render
            }
        }
    )
