/**
 * @use 部门管理表格 - 部门生失效切换，部门管理模块表格单元格中部门状态Switch切换时触发
 * @type Switch切换事件
 */
sysOrganGActiveAction(event: SwitchChangeEvent): void {
    const { context, data, newValue, setLoading, tableApi, node: tableNode, column } = event


    const group = OrganizationEventUtil.buildGroupByTreeData(data, 'END2#')

    const applyGroupStateChange = (): void => {
        this.organService.reverseGroupState(group, newValue).subscribe({
            next: res => {
                // 当前表格是否要过滤，该操作是生效还是失效
                const isFilter = context.getExtra(this.organGroupTableFilterKey) ?? true
                const isActive = newValue === 'Y'

                // 更新当前行数据
                tableNode.setDataValue(column.key, newValue)
                //失效 失效所有子阶
                if (!isActive) {
                    const updateChildren = (node: RowNode): void => {
                        node.children.forEach(i => {
                            i.setDataValue(column.key, newValue)
                            updateChildren(i)
                        })
                    }
                    updateChildren(tableNode)
                }
                // 生效 生效所有父阶
                else {
                    const updateParent = (node: RowNode): void => {
                        if (node.parentNode) {
                            node.parentNode.setDataValue(column.key, newValue)
                            updateParent(node.parentNode)
                        }
                    }
                    updateParent(tableNode)
                }

                //   const cellctrls = tableApi..getAllCellCtrls();
                //   cellctrls.forEach(ctrl => {
                //     if (ctrl.getColumnKey() === 'OPERATION$') {
                //       ctrl.refreshCell({
                //         forceRefresh: true
                //       });
                //     }
                //   });

                if (isFilter && !isActive) {
                    tableApi.onFilterChanged()
                }

                event.setLoading(false)
            },
            error: err => {
                event.setLoading(false)
            }
        })
    }

    if (newValue === 'Y') {
        applyGroupStateChange()
    } else {
        this.as.confirm(
            {
                content: 'systemSetting.organization.groupManagment.warning.invalid',
                title: 'common.operation.confirm.CheckIn.title',
                onOk: () => {
                    applyGroupStateChange()
                },
                onCancel: () => {
                    event.setLoading(false)
                }
            }
        )
    }
}

