public getRoute(node: RowNode): string[] {
    const path = []
    let currentNode = node
    while (currentNode) {
        path.unshift(currentNode.id!)
        currentNode = currentNode.parentNode!
    }
    return path
}

/**
 * @ToQY
 * @use 部门页面 - 保存按钮，部门编辑/新建页面底部"保存"按钮点击时触发
 * @type 通用事件接口
 */
sysOrgantGroupSaveAction(event: EventInterface): void {
    const formCpm = this.formRootFindChild<DppFormComponent>(event, CommandConstant.OrgantGroupTop)!
    const tableCpm = this.getTrigger<DppTableComponent>(event)
    const innerSend = formCpm.dppRender.innerSend as DppSafeAny
    const targetNode = innerSend?.getTargetNode() as RowNode
    if (!formCpm.onSubmit()) {
        return
    }
    const group = deepCopy(formCpm.getFormData<IGroup>()) as IGroup

    if (group.ROLELIST && group.ROLELIST.length > 0) {
        group.ROLELIST = group.ROLELIST.map(i => i.origin!) as any
    }
    this.setLoading(event, true)
    this.organService
        .saveGroup(group)
        .pipe(
            map(i => {
                if (group.GUID) {
                    this.organService.getGroup(group.GUID).subscribe(res => {
                        if (res.success) {
                            // let data = {};
                            // Object.keys(res.data!).forEach(key => {
                            //   data[`END2#${key}`] = res.data![key];
                            // });
                            // if (group['CALENDARGUID$TITLE']) {
                            //   data[`END2#CALENDARGUID$TITLE`] = group['CALENDARGUID$TITLE'];
                            // }
                        }
                    })
                }
                return i
            })
        )
        .subscribe({
            next: res => {
                this.setLoading(event, false)
                if (!res.success) {
                    return
                }
                formCpm.callback({
                    action: EventCallbacksActionName.UPDATE,
                    params: res.data
                })

                this.getTriggerDrawer(event)?.close()

                const isAdd = !group.GUID
                const route = this.getRoute(targetNode)
                if (isAdd) {
                    tableCpm.applyTransaction({
                        route: route,
                        add: [res.data]
                    })
                    targetNode.isExpanded = true
                } else {
                    // 更新
                    targetNode.setData({
                        ...targetNode.origin,
                        ...res.data
                    })
                }
            },
            error: err => this.setLoading(event, false)
        })
}

/**
 * @ToQY
 * @use 部门页面 - 保存并新建按钮，部门编辑/新建页面底部"保存并新建"按钮点击时触发
 * @type 通用事件接口
 */
sysOrgantGroupSaveNewAction(event: EventInterface): void {
    const formCpm = this.formRootFindChild<DppFormComponent>(event, CommandConstant.OrgantGroupTop)!
    const toolbar = this.formRootFindChild<DppToolbarComponent>(event, CommandConstant.OrgantGroupBottom)!
    const tableCpm = this.getTrigger<DppTableComponent>(event)
    const innerSend = formCpm.dppRender.innerSend as DppSafeAny
    const targetNode = innerSend?.getTargetNode() as RowNode
    const route = this.getRoute(targetNode)
    if (!formCpm.onSubmit()) {
        return
    }
    const group = deepCopy(formCpm.getFormData<IGroup>()) as IGroup

    if (group.ROLELIST && group.ROLELIST.length > 0) {
        group.ROLELIST = group.ROLELIST.map(i => i.origin!) as any
    }

