/**
 * @use 部门管理表格 - 导入部门，部门管理模块表格顶部"导入部门"按钮点击时触发
 * @type 表格顶部工具栏执行事件
 */
sysOrgantImportGroupAction(event: TableTopToolbarExecuteEvent): void {
    const { btnApi, tableApi } = event
    btnApi.setLoading(true)

    const fileInput = document.createElement('input')
    fileInput.type = 'file'
    fileInput.accept = '.csv,.xlsx,.xls'
    fileInput.style.display = 'none'
    fileInput.addEventListener('change', fileEvent => {
        const files = (fileEvent.target as HTMLInputElement).files

        this.organService.importGroup(files![0]).subscribe({
            next: res => {
                btnApi.setLoading(false)
                if (!res.success) {
                    return
                }
                if (res.data!.totalCnt === res.data!.successCnt) {
                    this.messageService.success('systemSetting.organization.groupManagment.title.importSuccess')
                } else {
                    const errDatas = new Array()
                    const errDatas_ = res.data!.details.filter(i => i.result !== 'SUCCESS')
                    errDatas_.map(i => {
                        let tranMess = ''
                        if (Array.isArray(i.message)) {
                            i.message.forEach((mess, index, arr) => {
                                const tran = this.tranPipe.transform(mess, i.data)
                                if (index !== arr.length - 1) {
                                    tranMess += `${tran};`
                                } else {
                                    tranMess += `${tran}`
                                }
                            })
                        } else {
                            tranMess = this.tranPipe.transform(i.message, i.data)
                        }
                        // i.message = tranMess;
                        errDatas.push({ ...i.data, message: tranMess, ROWCOUNT$: errDatas_.length })
                    })
                    this.messageService.customBatchMessage(
                        'error',
                        {
                            actionName: 'systemSetting.organization.groupManagment.title.import',
                            successCnt: res.data!.successCnt,
                            errorCnt: res.data!.errorCnt,
                            warnCnt: res.data!.errorCnt,
                            totalCnt: res.data!.totalCnt
                        },
                        () => {
                            const render: IRenderParameterNew<IUiModel> = {
                                name: 'sysOrganErrGroupTable',
                                mParams: {
                                    mode: ModeTypeEnum.EDIT,
                                    canSet: 'N',
                                    canExport: 'false',
                                    canSize: 'N',
                                    toolbar: 'sysOrganErrGroupToolbar'
                                },
                                data: errDatas as unknown as Record<string, unknown>,
                                dParams: {}
                            }
                            this.as.openModal<TableApi>(
                                {
                                    title: 'systemSetting.organization.groupManagment.field.failureReason',
                                    uiType: 'table',
                                    footer: 'noFooter',
                                    width: '80%',
                                    height: '70vh',
                                    params: {
                                        dppRender: render
                                    }
                                }
                            )
                        }
                    )
                }
                tableApi
                    .refreshData()
                    .subscribe(() => {
                        const firstNode = tableApi.getAllNodes()[0]
                        if (firstNode.hasChildren()) {
                            firstNode.isLoading = true
                        }
                    })
            },
            error: err => btnApi.setLoading(false)
        })
        fileInput.remove()
    })
    fileInput.addEventListener('cancel', fileEvent => {
        fileInput.remove()
        btnApi.setLoading(false)
    })
    fileInput.click()
}

