/**
 * 组织结构菜单点击事件
 * @param event 事件对象
 * @use 产品设计二级页面menu行点击
 */
sysOrganSMenuClick(event: EventInterface): void {
  const paramsKeysArr = ['GROUPGUID', 'ROLEGUID'];
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const menu = this.getExeCom(event) as DppMenuComponent;
  const selectNode = menu.getSelectedData()?.data;
  const params = {};

  paramsKeysArr.forEach(key => {
    params[key] = selectNode['origin']?.[key];
  });
  table.dppRender.dParams = table.dppRender.dParams || {};

  if (selectNode.type === 'role') {
    const origin = selectNode['origin'] as IRole;
    const rig: IRig = {
      GUID: origin.RIGGUID,
      GUID$: origin.RIGGUID,
      GROUPGUID: origin.GROUPGUID,
      GROUPID: origin.GROUPID,
      GROUPNAME: origin.GROUPNAME,
      ROLEGUID: origin.ROLEGUID,
      ROLEID: origin.ROLEID,
      ROLENAME: origin.ROLENAME
    };
    table.dppRender.dParams = table.dppRender.dParams || {};
    table.dppRender.dParams!['RIGLIST'] = [
      {
        label: `${rig.GROUPNAME}(${rig.ROLENAME})`,
        value: rig.GUID,
        origin: rig
      }
    ];
    table.dppRender.dParams['ISSELECTROLE'] = 'Y';
  } else {
    table.dppRender.dParams['ISSELECTROLE'] = 'N';
    table.dppRender.dParams!['RIGLIST'] = '';
  }
  table.topToolbar.dppRender.dParams = table.dppRender.dParams;
  table.topToolbar.refresh({
    params: table.dppRender.dParams as any
  });
  table.topToolbar.updateToolbar();
  table.refreshByParams(params);
}

