  const targetTable = this.getContentCom<DppTableComponent>(event);
  const data = this.getRowData(event);
  const beforeTemplateName = targetTable?.modelManager?.dataInfo?.params['templateName'];
  if (beforeTemplateName === data['TEMPLATENAME'] && targetTable.dppRender.dParams) {
    return;
  }
  if (targetTable?.modelManager?.dataInfo?.params) {
    targetTable.modelManager.dataInfo.params['templateName'] = data?.['TEMPLATENAME'];
