  // Y不能写死
  const childToolbar = targetTable?.topToolbar;
  const filterBtn = childToolbar?.service?.filterBtnsByName(
    'sysBomRelationFilterCommand',
    childToolbar.dppButtons.toArray()
  );
  const childValue = filterBtn?.value;
  let searchCondition = [new QueryConditionInfo('TEMPLATENAME', [data?.['TEMPLATENAME']], 'EQUAL')];
  if (childValue === 'Y') {
    searchCondition = [
      new QueryConditionInfo('ISVALID', [childValue], 'EQUAL'),
      new QueryConditionInfo('TEMPLATENAME', [data?.['TEMPLATENAME']], 'EQUAL')
    ];
  }
  targetTable.refreshByCondition(searchCondition);
}

