sysPerBatchDeleteAction(event: EventInterface): void {
    const table = this.getContentCom<DppTableComponent>(event)
    const selectDatas = table.getCheckedNodes().map(i => i.origin) as unknown as ACLItem[]
    const bs = this.getExeCom<DppButtonComponent>(event)
    this.permisService.batchDeleteACLItem(selectDatas).subscribe({
        next: res => {
            this.setLoading(event, false)
            if (!res.success) {
                return
            }
            if (res.data!.totalCnt === res.data!.successCnt) {
                this.dppMessageService.success('common.operation.operationSuccess')
            } else {
                const errDatas = new Array()
                res.data!.details.map(i => {
                    if (i.result !== 'SUCCESS') {
                        const findData = selectDatas.find(t => t.guid === i.data.GUID)
                        if (findData) {
                            errDatas.push({ ...findData, message: i.message })
                        }
                    }
                })
                this.dppMessageService.customBatchMessage(
                    'error',
                    {
                        actionName: bs.getUiModel().label,
                        successCnt: res.data!.successCnt,
                        errorCnt: res.data!.errorCnt,
                        warnCnt: res.data!.errorCnt,
                        totalCnt: res.data!.totalCnt
                    },
                    () => {
                        const render: IRenderParameterNew<IUiModel> = {
                            name: 'sysDataPermErrTable',
                            mParams: {
                                mode: ModeTypeEnum.EDIT,
                                canSet: 'N',
                                canExport: 'false',
                                canSize: 'N'
                                // width: '1300px'
                                // toolbar: 'sysOrganErrGroupToolbar'
                            },
                            data: errDatas as unknown as Record<string, unknown>,
                            dParams: {}
                        }
                        const modal = this.as.openModal(
                            {
                                title: 'systemSetting.organization.groupManagment.field.failureReason',
                                uiType: 'table',
                                isInteractive: true,
                                footer: 'noFooter',
                                width: '80%',
                                height: '70vh'
                            },
                            {
                                dppRender: render
                            }
                        )
                    }
                )
            }
            table.refreshData()
        },
        error: err => this.setLoading(event, false)
    })
}

/**
 * 处理包含有项目变更单的跳转函数
 * @param event 
 */
sysOpenBlankHasPMChangeAction(event: HasModelEventInterface, config?: BlankInterface): void {
  this.sysOpenGeneralBlankAction(event, {
    specialCaseFn: (specialConfig) => {
      const { baseUri, className, guid, rowData } = specialConfig;

      // 处理项目变更单（PMChange）类型的特殊跳转逻辑
      if (className == 'PMChange') {
        const property = {
          title: `${className}-${guid}`,
          baseUri,
          routePath: '/project-change-record-list'
        };
        const params = {
          dppRender: {
            CLASSNAME$: className,
            GUID$: guid,
            CLASSGUID$: rowData['CLASSGUID$'],
            FULLNAME$: rowData['FULLNAME$']
          }
        };
        this.as.openBlank(property, params);
        return false; // 阻止后续默认行为
      }
      // 其他类型继续执行默认处理流程
      return true;
    },
    ...(config || {})
  })
}

/**
 * 处理包含有项目变更单的打开抽屉函数
 * @param event 
 */
sysOpenDrawerHasPMChangeAction(event: HasModelEventInterface, config?: BlankInterface): void {
  this.sysOpenGeneralDrawerAction(event, {
    specialCaseFn: (handleConfig) => {
      const { property, model, newParams, baseUri, key, className, rowData, guid } = handleConfig;

      if (className == 'PMChange') {
        newParams['name'] = 'sysInstancePreviewPage';

        // 当前项目
        if (key === 'ppm' || !baseUri) {
          Object.assign(property, { uiType: 'page' });
        } else {
          // 其他项目
          newParams['mParams'] = newParams['mParams'] || {};
          newParams['mParams'][
            'src'
          ] = `/project-change-record-list?GUID$=${guid}&CLASSNAME$=${className}&CLASSGUID$=${rowData['CLASSGUID$']}&FULLNAME$=${rowData['FULLNAME$']}&name=sysInstancePreviewPage&noTop=true`;
          newParams['mParams']['baseUri'] = baseUri;
          Object.assign(property, { uiType: 'generalIframe' });
        }
        this.as.openDrawer({ ...property, closeOtherDrawer: false, title: '&nbsp;' }, { dppRender: newParams }, model);
        return false;
      }
      return true;
    },
    ...(config || {})
  });
}

