/**
 * 执行一般动作函数
 * 
 * 该函数用于处理一个通用动作事件，根据是否提供了特定配置来决定执行的动作
 * 它允许在不修改原有动作函数的情况下，引入特定场景下的特殊处理逻辑
 * 
 * @param event - 事件对象，包含模型事件的相关信息
 * @param actionFn - 动作函数，当事件触发时会被调用
 * @param config - 可选的空白配置对象，用于传递额外的配置信息
 */
private executeGeneralAction(
  event: HasModelEventInterface,
  actionFn: (handleConfig: CellClickGeneralCall) => void,
  config?: BlankInterface
): void {
  const handleConfig = this.cellClickGeneralAction(event, config);
  if (config) {
    config.handleConfig = handleConfig;
    if (config.specialCaseFn && typeof config.specialCaseFn === 'function') {

      // 如果执行完特殊处理逻辑后返回true,则继续执行默认逻辑
      if (config.specialCaseFn(handleConfig)) {
        actionFn.call(this, handleConfig)
      }
      return;
    }
  }
  actionFn.call(this, handleConfig);
}

/**
 * 打开系统通用抽屉函数
 * 该函数用于处理点击事件后打开抽屉的操作，根据不同的配置展示不同的内容
 * @param handleConfig - 包含抽屉配置的对象，包括属性、模型、参数等信息
 */
private sysOpenGeneralDrawerFn(handleConfig: CellClickGeneralCall): void {
  const { property, model, newParams, baseUri, key, className, guid } = handleConfig;
  // newParams['mParams'] = newParams['mParams'] || {};
  newParams['name'] = 'sysInstancePreviewPage';

  // 当前项目
  if (key === 'umc' || !baseUri) {
    Object.assign(property, { uiType: 'page' });
  } else {
    // 其他项目
    newParams['mParams'] = newParams['mParams'] || {};
    newParams['mParams']['src'] = `/page?className=${className}&guid=${guid}&name=sysInstancePreviewPage&noTop=true`;
    newParams['mParams']['baseUri'] = baseUri;
    Object.assign(property, { uiType: 'generalIframe' });
  }
  this.as.openDrawer(property, { dppRender: newParams }, model);
}

/**
* 打开新窗口的通用函数
* 该函数用于在点击表格单元格后，根据配置信息打开一个新的窗口或标签页
* 
* @param handleConfig 包含打开新窗口所需配置信息的对象
*/
private sysOpenGeneralBlankFn(handleConfig: CellClickGeneralCall): void {
  const { baseUri, className, guid, windowName, rowData, originConfig } = handleConfig;
  let routePath = `/instance?className=${className}&guid=${guid}`;

  // 额外参数
  if (originConfig?.extraKeys) {
    originConfig?.extraKeys.map(item => {
      if (item.includes(':')) {
        const sliceArr = item.split(':');
        routePath += `&${sliceArr[0]}=${rowData[sliceArr[1]]}`;
      } else {
        routePath += `&${item}=${rowData[item]}`;
      }
    });
  }
  // this.as.openBlank(property, { dppRender: model.action });
  this.as.openBlank({ routePath, baseUri, title: windowName });
}

/**
 * 单元格点击通用处理
 * @param event
 * @returns
 */
cellClickGeneralAction(event: HasModelEventInterface, config?: BlankInterface): CellClickGeneralCall {
  let { classNameKey = 'CLASSNAME$', guidKey = 'GUID$', extraParams } = config || {};
  const rowData = this.getRowData(event as EventInterface);
  let data = rowData;
  if (extraParams) {
    data = Object.assign(rowData, extraParams);
  }
  const model = event.model as ButtonIUiModel;
  const modelProperty = model?.action as Property;

  if (modelProperty?.['classNameKey']) {
    classNameKey = modelProperty['classNameKey'];
  }

  if (modelProperty?.['guidKey']) {
    guidKey = modelProperty['guidKey'];
  }

  let revisionKey = 'REVISIONID$';
  let iterationKey = 'ITERATIONID$';
  if (config?.dataKey) {
    const key$ = config?.dataKey.indexOf('$') !== -1 ? config?.dataKey : config?.dataKey + '$';
    guidKey = config?.dataKey;
    classNameKey = `${key$}CLASSNAME`;
    revisionKey = `${key$}REVISIONID`;
    iterationKey = `${key$}ITERATIONID`;
  }

  const className = config?.className || data[classNameKey];
  const guid = config?.guid || data[guidKey];
  const revisionid = data[revisionKey];
  const iterationid = data[iterationKey];
  let windowName = `${className}-${guid}-${revisionid}-${iterationid}`;

  // 额外参数
  if (config?.extraTitleKeys) {
    config?.extraTitleKeys.map(item => {
      if (item.includes(':')) {
        const sliceArr = item.split(':');
        windowName += `-${data[sliceArr[1]]}`;
      } else {
        windowName += `-${data[item]}`;
      }
    });
  }

  const needHandleKeys = ['closeOtherDrawer', 'closable', 'mask', 'isInteractive'];
  for (let propertyKey in modelProperty) {
    if (needHandleKeys.includes(propertyKey)) {
      modelProperty[propertyKey] = strBoolean(modelProperty[propertyKey]);
    }
  }
  let key = 'pdm';
  // 属性公用部分
  let property: Property = {
    title: generateTitle(model, data, this.injector),
    mask: false,
    isInteractive: true,
    closable: true,
    closeOtherDrawer: true,
    wrapClassName: `drawer${guid}-${className}`,
    ...modelProperty
  };
  // 判断baseUri
  let baseUri = data['BASEURI'];
  if (!baseUri) {
    // 后端没有返回的情况下，内置支持ppm和pdm的区分
    const toPpmClassNames = ['ProjectTemplate', 'Project', 'PMTask', 'PMTaskTemplate', 'PMChange'];
    key = toPpmClassNames.includes(className) ? 'ppm' : 'pdm';
    baseUri = this.configService.getConfig()[key];
  } else {
    key = baseUri;
  }
  // 处理参数
  let params = handleRenderParam(
    model?.action as unknown as Record<string, string> || {},
    data as Record<string, string>,
    this.express,
    true
  );
  let newParams = assembTileParams(params);
  // 如果模型中没有配置数据参数，则使用内置的key去取
  if (!params['guid'] && guid && newParams['dParams']) {
    newParams['dParams']['guid'] = guid;
    newParams['dParams']['className'] = className;
  }

  if (config?.extraDParams) {
    newParams['dParams'] = Object.assign(newParams['dParams']!, config.extraDParams);
  }
  return {
    property,
    model,
    newParams,
    baseUri,
    key,
    className,
    guid,
    windowName,
    rowData,
    extraParams,
    originConfig: config!
  };
}

