/**
 * 下载附件
 * @param event
 * @use 高级搜索页面
 */
sysStartDonwloadAction(event: EventInterface): void {
  this.setLoading(event, true);
  const rowData: IFoundaton = this.getRowData(event);
  const classguid = rowData['CLASSGUID$']!;
  const guid = rowData['GUID$']!;
  this.downloadAttach(guid, classguid).subscribe({
    next: res => {
      if (res.success && res.data) {
        const url = window.URL.createObjectURL(res.data);
        const link = document.createElement('a');
        link.target = '_blank';
        console.log(rowData['ID$']);
        link.download = `${rowData['ID$']}.zip`;
        link.href = url;
        link.click();
        window.URL.revokeObjectURL(url);
        this.dppMessageService.success('common.operation.operationSuccess');
      }
      this.setLoading(event, false);
    },
    error: err => {
      this.setLoading(event, false);
    }
  });
}

public downloadAttach(
  guid: string,
  classGuid: string,
  boGuidList?: string[],
  fileTypeList?: string[]
): Observable<DppResponse<Blob>> {
  const headers = createHeaders(this.authUser);
  const requestBody = {
    guid,
    classGuid,
    boGuidList,
    fileTypeList
  };
  const url = this.configService.getConfig().apiUrl + UMCUrlConfig.commonModel.downloadAttach;
  return this.httpOrigin
    .post(url, requestBody, {
      responseType: 'blob',
      headers
    })
    .pipe(
      map(res => {
        return { success: true, data: res as Blob, errorMsg: '', errorCode: '' };
      })
    );
}

