// 关联模板过滤
sysAssociationTemplateFilterAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const rootPage = this.getRootPageService(event) as IPageService;
  const filterFn = (): void => {
    const button = this.getExeCom<DppButtonComponent>(event);
    const value = button.value;

    table.refreshByParams({ ISVALID: value }).subscribe(res => {
      table.setNodeSelected(0);
      const selectNode = table.getSelectedNodeList()[0];
      const templateName = selectNode?.origin?.['TEMPLATENAME'] || '';
      const childTable = rootPage.getComFnMapByName<DppTableComponent>('sysRelationBusinessObjectTableCommand');
      const childToolbar = childTable?.topToolbar;
      const filterBtn = childToolbar?.service?.filterBtnsByName(
        'sysAssociationBusinessFilterCommand',
        childToolbar.dppButtons.toArray()
      );
      const childValue = filterBtn?.value;
      childTable?.refreshByParams({ templateName, ISVALID: childValue });
    });
  };
  table.beans.event.conditionReady$.subscribe(res => {
    if (res) {
      filterFn();
    }
  });
}

// 关联业务对象过滤
sysAssociationBusinessFilterAction(event: EventInterface): void {
  const table = this.getContentCom<DppTableComponent>(event);
  const rootPage = this.getRootPageService(event);
  const parentTable = rootPage.getComFnMapByName<DppTableComponent>('sysRelationTemplateTableCommand');
  const selectNode = parentTable?.getSelectedNodeList()[0];
  const templateName = selectNode?.origin?.['TEMPLATENAME'];
  const button = this.getExeCom<DppButtonComponent>(event);
  const value = button.value;
  let condition: QueryConditionInfo[] = [];
  condition = [new QueryConditionInfo('templateName', [templateName], 'EQUAL')];
  if (value === 'Y') {
    condition.push(new QueryConditionInfo('ISVALID', [value], 'EQUAL'));
  }
  table.refreshByParams({ templateName, ISVALID: value });
}

