// 关联模板生失效
async sysAssociationTemplateUpdateValidAction(event: SwitchChangeEvent): Promise<void> {
  const newValue = event.newValue;

  const applyRelationChange = (): void => {
    const data = event.data;
    const templateName = data['TEMPLATENAME'];
    const isvalid = newValue;
    event.setLoading(false);
    this.relationManagement.toggleRelationTemplate({ templateName, isvalid }).then(res => {
      event.fetchTableData();
    })
  };

  const onCancel = (): void => {
    event.setLoading(false);
  };

  // 当前操作是生效还是失效
  if (newValue === 'Y') {
    applyRelationChange();
  } else {
    const contentStr = `systemSetting.relationTemplate.message.isVaildTemplateConfirm`;
    this.relationTool.openConfirm(contentStr, applyRelationChange, onCancel);
  }
}

