// 流程模板搜索
sysWFTemplateSearchAction(event: EventInterface): void {
  const button: DppButtonComponent = this.getExeCom<DppButtonComponent>(event);
  const table = this.getContentCom(event) as DppTableComponent;
  const inputvalue: string = button.value;
  const searchCondition = new QueryCondition(DppQueryConditionOperator.AND);

  const com = this.getExeCom<DppButtonComponent>(event);
  const toolbar = com.toolbarComFn() as DppToolbarComponent;
  const btnList = toolbar['dppButtons']?.toArray();
  const btn = toolbar?.service?.filterBtnsByName('sysWFTFilterConditionCommand', btnList);
  let keys = ['TITLE'];
  let values = [inputvalue];

  if (btn?.value === 'Y') {
    keys = ['TITLE', 'ISVALID'];
    values = [inputvalue, btn?.value];
  }
  const operators = [DppQueryConditionOperator.LIKE, DppQueryConditionOperator.EQUALS];

  keys.forEach((key, index) => {
    searchCondition.addCondition(new QueryConditionInfo(key, [values[index]], operators[index]));
  });
  table.refreshByCondition(searchCondition);
}

// 表格过滤(所有模板/仅生效模板)
sysWFSelectTemplateAction(event: EventInterface): void {
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const state = event.event as unknown as string;

  const com = this.getExeCom<DppButtonComponent>(event);
  const toolbar = com.toolbarComFn() as DppToolbarComponent;
  const btnList = toolbar['dppButtons']?.toArray();
  const btn = toolbar?.service?.filterBtnsByName('sysWFTemplateSearchCommand', btnList);
  let keys = ['TITLE'];
  let values = [btn?.value ? btn?.value : ''];
  if (state === 'Y') {
    keys = ['TITLE', 'ISVALID'];
    values = [btn?.value ? btn?.value : '', state];
  }
  const operators = [DppQueryConditionOperator.LIKE, DppQueryConditionOperator.EQUALS];

  const condition = new QueryCondition(DppQueryConditionOperator.AND);
  keys.forEach((key, index) => {
    condition.addCondition(new QueryConditionInfo(key, [values[index]], operators[index]));
  });
  table.refreshByCondition(condition);
}

private _searchAdd(condition: QueryCondition, value: string): QueryCondition {
  const keys = ['TITLE'];
  keys.forEach(itey => {
    condition.addCondition(new QueryConditionInfo(itey, [value], DppQueryConditionOperator.LIKE));
  });
  return condition;
}

// 生失效更新
sysWFUpdateValidAction(event: SwitchChangeEvent): void {
  const data = event.data;
  const newValue = event.newValue;

  const applyWorkflowTemplateStateChange = (): void => {
    const ISVALID = newValue;
    const wfTemplateGuid = data['GUID'];

    this.wfTemplateService.reverseWorkflowTemplateState({ wfTemplateGuid, ISVALID }).subscribe({
      next: res => {
        event.fetchTableData();
      },
      error: err => {
        event.setLoading(false);
      }
    });
  };

  if (newValue === 'Y') {
    applyWorkflowTemplateStateChange();
  } else {
    const content = 'systemSetting.workflowTemplate.detail.prompt.warningContent';
    const title = 'systemSetting.workflowTemplate.detail.field.warning';
    this.as.confirm({
      content,
      title,
      onOk: ctx => {
        applyWorkflowTemplateStateChange();
      },
      onCancel: ctx => {
          event.setLoading(false);
      }
    }
    );
  }
}

