// 复制新建
sysWFTCopyAndNewAction(event: EventInterface): void {
  const model = this.getExeModel(event);
  const title = this.dpptranslate.transform(model.label!);
  const table = this.getContentCom(event) as unknown as DppTableComponent;
  const rowData = this.getRowData(event) as DppTableComponent;
  const params = {
    wfTemplateGuid: rowData['GUID']
  };

  const name = rowData['WFNAME$TITLE'];
  this.wfTemplateService.getWorkflowTemplateDetail(params).subscribe({
    next: res => {
      if (res.success) {
        const params = {
          dParams: { ...res.data },
          innerSend: table,
          data: {
            type: 'copyNew'
          }
        };
        const drawer = this.as.openDrawer(
          {
            title: title,
            drawerSelf: () => drawer,
            width: '60vw',
            style: {
              position: 'relative'
            },
            content: FlowSettingComponent
          },
          {
            dppRender: params
          }
        ) as DppNzDrawerRef;
      }
    }
  });
}

