// 选择对象及分类的移除
sysWFSelectOCRemoveAction(event: EventInterface): void {
  const rowData = this.getRowData(event);
  const node = this.getNode(event) as RowNode;
  const table = this.getContentCom(event) as DppTableComponent;
  const allData = this.getData(event) as IBaseData[];
  const tableDataKeys = allData
    .filter(item => item['GUID'] !== rowData['GUID'])
    .map(item => {
      if (item['TYPE'] === 'BUSINESS_OBJECT') {
        return item['BOGUID'];
      } else {
        return item['CLASSIFICATION'];
      }
    });
  const classfieldCpn = table['dppRender']?.['InnerSend']?.['triggerInstance']?.();

  if (classfieldCpn) {
    classfieldCpn.setCheckedByKeys(tableDataKeys);
  }

  table.deleteNode([node]);
}
